window.__LIBQ=window.__LIBQ||{};window.__LIBQ["the-gioi-hoan-my"]=window.__LIBQ["the-gioi-hoan-my"]||{};window.__LIBQ["the-gioi-hoan-my"]["q01"]=window.__LIBQ["the-gioi-hoan-my"]["q01"]||{};window.__LIBQ["the-gioi-hoan-my"]["q01"]["characters"]={"updatedAt":"2026-07-01","count":31,"chars":[{"id":"chu-nhoc-than-thon","name":"Chú nhóc (chưa đặt tên)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (@c0001)","trangThai":"song","blurb":"Bé trai khoảng một tuổi rưỡi ở Thạch Thôn, mồ côi cha mẹ từ nửa tuổi, bú sữa bách thú mà lớn lên.","vaiTro":"Nhân vật chính tiềm năng — đứa trẻ mồ côi được lão tộc trưởng Thạch Thôn chăm sóc đặc biệt.","tinhCach":[{"text":"Hiếu động, mê đuổi theo chim sẻ năm màu, vấp ngã liên tục mà không khóc.","chuong":"@c0001"},{"text":"Ngây ngô vô tư, bị đám trẻ lớn trêu mà chỉ cười không để bụng.","chuong":"@c0001"}],"tabs":{"diem":[{"text":"Mồ côi cha mẹ từ nửa tuổi, sống nhờ sữa bách thú do tộc trưởng nuôi.","chuong":"@c0001"},{"text":"Trắng trẻo xinh xắn, mắt đen láy như búp bê sứ, thân thế bí ẩn.","chuong":"@c0001"}],"kinhLich":[{"text":"Chú nhóc một tuổi rưỡi trà trộn vào đám trẻ rèn luyện dưới mây sớm, bi bô bắt chước động tác, sau đó đuổi theo con chim sẻ năm màu. Được lão tộc trưởng Thạch Vân Phong nấu sữa thú cho ăn, vẫn không chịu cai sữa.","anchor":"Chú nhóc mất cha mẹ từ khi mới nửa tuổi, bú sữa bách thú lớn lên","bridge":true,"khoang":"@c0001"},{"importance":"normal","chuong":"@c0001","tieuDe":"Trà trộn rèn luyện và bú sữa thú","text":"Chú nhóc mới tập đi tự bám theo đám trẻ rèn luyện thân thể dưới mây sớm, bi bô bắt chước động tác xiêu vẹo. Mồ côi từ nửa tuổi, bú sữa bách thú lớn lên, nay được hơn một tuổi vẫn chưa cai sữa nên bị đám trẻ lớn trêu, song nó không để bụng mà múc sữa uống ngon lành.","anchor":"Chú nhóc mất cha mẹ từ khi mới nửa tuổi, bú sữa bách thú lớn lên"},{"importance":"normal","chuong":"@c0001","tieuDe":"Trà trộn rèn luyện, đuổi chim sẻ","text":"Chú nhóc một tuổi rưỡi tự bám theo đám trẻ rèn luyện dưới mây sớm, rồi chạy đuổi theo con chim sẻ năm màu, vấp ngã liên tục nhưng không khóc.","anchor":"nó không khóc mà tức tối lồm cồm bò dậy tiếp tục đuổi theo"},{"importance":"normal","chuong":"@c0001","tieuDe":"Mồ côi nuôi bằng sữa bách thú","text":"Lão tộc trưởng Thạch Vân Phong nấu sữa thú bỏ dược thảo nuôi chú nhóc — đứa trẻ mất cha mẹ từ nửa tuổi, nay vẫn chưa cai sữa.","anchor":"Chú nhóc mất cha mẹ từ khi mới nửa tuổi, bú sữa bách thú lớn lên"},{"text":"Theo yêu cầu lũ trẻ, nhóc tỳ giơ hai bàn tay dùng sức, một quầng sáng và ký tự kỳ lạ như đúc kim loại nổi lên trên lòng bàn tay, nhấc bổng khối đá xanh còn cao hơn người mình rồi ném xuống cười vô tư — khiến lũ trẻ kinh ngạc.","anchor":"lòng bàn tay nó xuất hiện một quầng sáng, một kí tự kì lạ nổi lên","bridge":true,"khoang":"@c0002"}],"tuViMoc":[{"chuong":"@c0001","canhGioi":"Phàm nhân","text":"Còn là bé trai một tuổi rưỡi ở Thạch Thôn, chưa tu luyện.","importance":"minor"}],"nhanMach":[{"ten":"Thạch Vân Phong","tag":"an-nhan","quanHe":"Người chăm sóc","ghiChu":"Lão tộc trưởng nấu sữa thú nuôi chú nhóc mồ côi từ nhỏ."},{"ten":"Thạch Vân Phong","tag":"an-nhan","quanHe":"Người nhận nuôi","ghiChu":"Được Thạch Vân Phong nhận nuôi và làm đối tượng nghiên cứu cốt văn tốt nhất"},{"ten":"Thạch Vân Phong","tag":"an-nhan","quanHe":"Lão tộc trưởng nấu sữa thú nuôi dưỡng chú nhóc.","ghiChu":"Chăm sóc chú nhóc mồ côi tại nhà mình ở đầu thôn."},{"ten":"Thạch Vân Phong","tag":"an-nhan","quanHe":"Lão tộc trưởng nuôi dưỡng","ghiChu":"Nấu sữa bách thú trộn dược thảo nuôi chú nhóc mồ côi"}],"tuiDo":{}},"uuTien":100,"nguon":["@c0001","@c0002"]},{"id":"thach-van-phong","name":"Thạch Vân Phong","cn":"","aliases":["lão tộc trưởng","Lão tộc trưởng"],"gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (@c0001)","trangThai":"song","blurb":"Lão tộc trưởng Thạch Thôn, râu tóc bạc phơ, tinh khí thần sung túc.","vaiTro":"Lão tộc trưởng đứng đầu Thạch Thôn, chủ trì việc cầu khấn Tế Linh và quyết định lớn của thôn.","tinhCach":[{"text":"Điềm tĩnh, từng trải, nhạy bén nhận ra dấu hiệu dị biến trong núi.","chuong":"@c0001"},{"text":"Nhân hậu, đích thân nấu sữa thú nuôi đứa trẻ mồ côi.","chuong":"@c0001"}],"tabs":{"diem":[{"text":"Lão tộc trưởng đứng đầu Thạch Thôn, được tộc nhân kính trọng.","chuong":"@c0001"},{"text":"Nhận định sâu Đại Hoang có dị biến thu hút chủng tộc Thái Cổ.","chuong":"@c0001"}],"kinhLich":[{"text":"Trong cuộc bàn với các bậc trưởng lão, Thạch Vân Phong nhận định sâu trong Đại Hoang có thể xuất hiện thứ không tầm thường, thu hút các chủng tộc sót lại từ Thái Cổ kéo đến.","anchor":"Có lẽ nào đã xuất hiện sơn bảo?","bridge":true,"khoang":"@c0001"},{"importance":"normal","chuong":"@c0001","tieuDe":"Chủ trì lễ cầu Tế Linh","text":"Khi đội săn chuẩn bị vào núi vì sắp hết thức ăn, Thạch Vân Phong dẫn đầu mấy chục thanh niên cầu khấn trước gốc liễu già, xin Tế Linh bảo hộ săn bắn bình an.","anchor":"đời đời cúng tế phụng dưỡng người"},{"importance":"normal","chuong":"@c0001","tieuDe":"Bàn dị tượng và chủ trì cầu khấn Tế Linh","text":"Sau bữa sáng, Thạch Vân Phong cùng các bô lão bàn về việc hồng hoang hung thú đêm đêm đi qua, cho rằng sâu trong Đại Hoang xuất hiện thứ không tầm thường thu hút chủng tộc Thái Cổ kéo đến. Khi đội săn chuẩn bị vào núi, ông dẫn đầu cầu khấn trước gốc liễu già, khấn Tế Linh bảo hộ tộc nhân săn được thịt thú và bình an trở về.","anchor":"sâu trong Đại Hoang có khả năng đã xuất hiện thứ gì đó không tầm thường"},{"importance":"normal","chuong":"@c0001","tieuDe":"Bàn dấu hiệu nguy hiểm trong núi","text":"Thạch Vân Phong cùng các bô lão bàn về dấu hiệu bất thường nhiều đêm, cho rằng sâu trong Đại Hoang xuất hiện thứ không tầm thường thu hút các chủng tộc Thái Cổ kéo đến.","anchor":"nhất định là có hồng hoang hung thú đại trùng đi ngang qua đây"},{"importance":"normal","chuong":"@c0001","tieuDe":"Dẫn đầu lễ cầu khấn Tế Linh","text":"Trước khi đội săn vào núi, Thạch Vân Phong nghiêm trang dẫn đầu mấy chục thanh niên cầu khấn Tế Linh trước gốc liễu già, xin bảo hộ tộc nhân săn được thịt và bình an trở về.","anchor":"xin hãy bảo hộ tộc nhân, để lũ trẻ săn được thịt thú béo tốt, bình an trở về"},{"importance":"normal","chuong":"@c0001","tieuDe":"Bàn dấu hiệu nguy hiểm và cầu khấn Tế Linh","text":"Lão tộc trưởng Thạch Vân Phong nấu sữa thú nuôi chú nhóc mồ côi, chủ trì cuộc bàn luận của các bô lão về dấu hiệu bất thường trong núi (bọn lớn xác đi qua đêm, chủng tộc Thái Cổ kéo đến), rồi dẫn đầu lễ cầu khấn Tế Linh trước gốc liễu già xin bảo hộ đội săn bình an.","anchor":"xin hãy bảo hộ tộc nhân, để lũ trẻ săn được thịt thú béo tốt, bình an trở về"},{"importance":"normal","chuong":"@c0001","tieuDe":"Bàn dấu hiệu nguy hiểm trong núi","text":"Lão tộc trưởng Thạch Thôn chủ trì bàn luận với các bô lão về dấu hiệu bất thường, cho rằng sâu trong Đại Hoang xuất hiện thứ không tầm thường thu hút các chủng tộc sót lại từ Thái Cổ kéo đến.","anchor":"nhất định là có hồng hoang hung thú đại trùng đi ngang qua đây"},{"importance":"normal","chuong":"@c0001","tieuDe":"Chủ trì lễ cầu khấn Tế Linh","text":"Thạch Vân Phong dẫn đầu mấy chục thanh niên cầu khấn nghiêm trang trước gốc liễu già trước khi đội săn vào núi, xin Tế Linh bảo hộ tộc nhân săn được thịt thú và bình an trở về.","anchor":"xin hãy bảo hộ tộc nhân, để lũ trẻ săn được thịt thú béo tốt, bình an trở về"},{"text":"Sau lễ tiễn đội săn vào núi, Thạch Vân Phong dẫn lũ trẻ về bãi cỏ đầu thôn giảng giải cốt văn — những ký tự hiển hóa bẩm sinh trên xương cốt của chủng tộc mạnh mẽ thời Thái Cổ, học thành sẽ mạnh hơn thế hệ cha chú nhiều lần.","anchor":"cốt văn là những kí tự hiển hóa bẩm sinh trên xương cốt của một chủng tộc mạnh mẽ thời Thái Cổ","bridge":true,"khoang":"@c0002"},{"importance":"normal","chuong":"@c0002","tieuDe":"Kể chuyện thế giới bên ngoài","text":"Lão kể hồi trẻ từng cùng hơn mười tộc nhân cường đại xông pha thế giới bên ngoài, chỉ hai người đẫm máu trở về và một người sớm chết, chỉ mình lão sống sót; lão giảng về Đại Hoang rộng lớn và các chủng tộc Thái Cổ, tay sờ miếng ngọc cốt kỳ dị trong ngực áo với ánh mắt khác thường.","anchor":"chỉ có hai người toàn thân đẫm máu trở về, một trong số đó không lâu sau thì chết, chỉ có một mình Thạch Vân Phong sống sót"},{"importance":"normal","chuong":"@c0002","tieuDe":"Lập đài tế bên gốc liễu già","text":"Trước tin dấu chân khổng lồ trong núi, tộc trưởng dẫn mọi người về phía gốc liễu già, vác xác mấy chục con thú đặt lên bục đá làm đài tế cỡ lớn.","anchor":"đặt toàn bộ lũ hung thú dính đầy vết máu lên trên bục đá, rõ ràng đây là một đài tế cỡ lớn"},{"importance":"normal","chuong":"@c0002","tieuDe":"Hé lộ quá khứ sống sót","text":"Lão kể từng cùng hơn mười tộc nhân cường đại xông pha thế giới bên ngoài, chỉ hai người đẫm máu trở về, một người sớm chết, chỉ mình lão sống sót; nhiều năm nghiên cứu cốt văn từng lấy người khỏe mạnh làm thí nghiệm.","anchor":"chỉ có hai người toàn thân đẫm máu trở về, một trong số đó không lâu sau thì chết, chỉ có một mình Thạch Vân Phong sống sót"},{"importance":"normal","chuong":"@c0002","tieuDe":"Dạy cốt văn cho lũ trẻ","text":"Sau lễ tiễn đội săn, lão dẫn lũ trẻ về bãi cỏ đầu thôn dạy cốt văn dù chúng chán nản, giảng giải cốt văn là ký tự hiển hóa bẩm sinh trên xương cốt một chủng tộc mạnh thời Thái Cổ.","anchor":"cốt văn là những kí tự hiển hóa bẩm sinh trên xương cốt của một chủng tộc mạnh mẽ thời Thái Cổ"},{"text":"Dẫn già trẻ gái trai Thạch Thôn bước lên đàn tế cầu khấn cây liễu già phù hộ dân làng sau buổi săn bội thu; giải thích Tế Linh quý ở tấm lòng thành, thành kính đối đãi thì người mới phù hộ thôn.","anchor":"mong cây liễu phù hộ dân làng","bridge":true,"khoang":"@c0003"},{"importance":"normal","chuong":"@c0003","tieuDe":"Hé lộ hai đời Tế Linh","text":"Giải thích Tế Linh là Linh mà bộ tộc cúng tế phụng dưỡng, bảo vệ thôn làng chấn nhiếp hung thú Đại Hoang; tiết lộ đời trước là một hòn đá lạ hấp thu quá nửa tinh huyết vật tế, đời nay là cây liễu già không đụng cống phẩm.","anchor":"Tế Linh là Linh mà chúng ta cúng tế và phụng dưỡng, quý ở tấm lòng thành"},{"importance":"normal","chuong":"@c0003","tieuDe":"Hồi tưởng đêm cây liễu giáng trần","text":"Khi còn là thiếu niên, tận mắt thấy đêm mưa sấm chớp rạch trời: một cây liễu cao lớn chọc trời từ tầng mây xuất hiện, ngàn vạn cành liễu hóa xích thần đâm xuyên tầng không như đang chiến đấu, cuối cùng bị chém đứt cháy đen thu nhỏ rơi xuống cắm rễ Thạch Thôn; cùng đêm hòn đá lạ bỏ đi.","anchor":"một cây liễu cao lớn chọc trời từ trên tầng mây xuất hiện"},{"importance":"normal","chuong":"@c0003","tieuDe":"Chỉ huy mổ xẻ thu hung thú quý","text":"Dặn dò trai tráng cẩn thận giữ huyết tinh, gân mạch, xương cốt quý khi mổ xẻ cự thú; gật đầu khen voi sừng rồng có sừng là thuốc bổ cốt quý, dặn cẩn thận cưa sừng rồng.","anchor":"cả thôn làng vui như trẩy hội"},{"importance":"normal","chuong":"@c0004","tieuDe":"Chủ trì tắm thuốc cho nhóc tỳ","text":"Thạch Vân Phong chủ trì việc tắm thuốc trong hắc đỉnh đặc biệt cho nhóc tỳ. Lão mở hai bình đ���c biệt, dùng cốt văn sáng trong lòng bàn tay vỗ tan con Tỳ Hưu dài bằng bàn tay và đập tan con tê giác hai đầu đỏ rực, cả hai hóa huyết dịch rơi vào đỉnh.","anchor":"Một chiếc bình khác phóng ra một con tê giác hai đầu, đỏ rực như lửa"},{"importance":"normal","chuong":"@c0004","tieuDe":"Nấu lô bảo dược riêng","text":"Lão tự tay cầm chùy Tử Kim đập đoạn quý nhất trên sừng voi sừng rồng, thêm xương móng vuốt Tỳ Hưu và sừng đỏ Hỏa Tê mài bột, trộn chân huyết bỏ vào nồi sữa thú cùng thảo dược kỳ dị nấu thành chất sệt thơm ngào ngạt cho nhóc tỳ, rồi hài lòng nhìn nó hấp thu mạnh.","anchor":"Lão cầm một cây chùy Tử Kim đập vỡ một đoạn quý giá nhất trên sừng của con voi sừng rồng"},{"importance":"normal","chuong":"@c0006","tieuDe":"Hé lộ quá khứ đổi máu lấy cốt thư","text":"Tộc trưởng kể năm xưa cùng hơn mười huynh đệ đi xa đến các thế tộc môn đình, đổi máu và mạng đem về ít cốt thư; cuối cùng chỉ mình lão sống sót trở về, mang một thân ám tật, còn ẩn tình chưa kể.","anchor":"cuối cùng chỉ còn một mình tộc trưởng sống sót, để lại một thân ám tật"},{"importance":"normal","chuong":"@c0006","tieuDe":"Chưng cất huyết dược chuẩn bị tẩy lễ","text":"Lo khởi điểm Thạch Hạo thấp, Thạch Vân Phong ngày đêm chưng cất dược thảo, dùng cốt văn chưng cất tinh hoa máu mãnh thú thành huyết dược để chuẩn bị tẩy lễ năm tuổi cho Thạch Hạo, mỗi con thú cuối cùng chỉ còn một giọt máu vào bình ngọc.","anchor":"mỗi con mãnh thú cuối cùng chỉ rơi ra một giọt chảy vào trong bình ngọc"},{"chuong":"@c0009","importance":"normal","tieuDe":"Điều đội cứu viện mang Tổ Khí","text":"Hay tin Thanh Lân Ưng làm loạn gần thôn và đám nhóc lâm nguy, tộc trưởng Thạch Vân Phong ra lệnh lấy hai cái Tổ Khí, dẫn nhóm đàn ông cường tráng nhất lên đường cứu; ngoài động lệnh mọi người tụ lại phòng thủ để Thạch Lâm Hổ tế Tổ Khí.","anchor":"Mau đi lấy hai cái Tổ Khí lại đây, chúng ta cùng nhau đi!"},{"importance":"normal","chuong":"@c0010","tieuDe":"Chỉ huy rút lui khỏi ma cầm","text":"Ra lệnh tế hai Tổ Khí đe dọa Thanh Lân Ưng rồi thừa cơ dẫn dân rút về thôn, viện cớ cốt văn của Lâm Hổ và Phi Giao chưa tinh thâm khó phát huy uy lực thật; lo dùng tổ khí gây biến cố. Kể lại đại chiến Thái Cổ hai năm trước với lửa đỏ cháy mấy chục ngày.","anchor":"trình độ cốt văn của Lâm Hổ và Phi Giao không hề tinh thâm đến mức đó"},{"importance":"normal","chuong":"@c0011","tieuDe":"Nhận định trứng phản tổ","text":"Nhận ra quả trứng bị cành liễu phất qua đã xảy ra phản tổ, Sinh mệnh lạc ấn truyền thừa từ Thái Cổ Ma Cầm hồi phục, phán rằng nếu nở sẽ vượt xa Thanh Lân Ưng. Vì lo hung cầm nổi điên, ông quyết định trả trứng, rồi giải thích ý đồ Thanh Lân Ưng tặng lại ba trứng cho tộc nuôi làm Tế Linh.","anchor":"Quả trứng này nếu nở ra khẳng định sẽ vượt xa Thanh Lân Ưng!"},{"importance":"normal","chuong":"@c0012","tieuDe":"Xác nhận Bí Cốt Bảo Thư","text":"Tộc trưởng kinh động khi Thạch Hạo thi triển bảo phù, xác nhận phù văn đó có thể xưng Bí Cốt Bảo Thư và dặn không đến lúc mấu chốt đừng tùy tiện thi triển.","anchor":"Sau này không đến lúc mấu chốt, đừng có tùy tiện thi triển."},{"importance":"normal","chuong":"@c0013","tieuDe":"Cứu chữa Thủ Sơn, ứng phó Bái Thôn","text":"Rút mũi tên sắt khỏi người Thạch Thủ Sơn, dùng hào quang trong lòng bàn tay ấn ký hiệu cầm máu khép vết thương, rồi cho hai viên thuốc tím trị thương. Phán đoán Bái Thôn nay hùng mạnh nên tâm tư lớn dần, dặn Thạch Lâm Hổ phòng bị cẩn thận, đoán trong Bái Thôn đã xảy ra chuyện gì đó.","anchor":"lòng bàn tay lóe hào quang, ký hiệu sáng lên như sao"},{"importance":"normal","chuong":"@c0016","tieuDe":"Nghe bẩm báo về Toan Nghê","text":"Tộc trưởng nhận bẩm báo về con Toan Nghê Thái Cổ Di Chủng sắp chết già rít gào trong núi, cân nhắc việc rút chân huyết và khắc Nguyên Thủy Bảo Phù trên bộ xương như mở kho báu động trời.","anchor":"con Toan Nghê kinh khủng ở sâu trong dãy núi"},{"importance":"normal","chuong":"@c0017","tieuDe":"Quyết định vào núi lấy di thể Toan Nghê","text":"Tộc trưởng cảnh báo không được hành động tùy tiện, phải kiên nhẫn chờ. Khi Toan Nghê ra ngoại vi chết già, ông quyết định dẫn cả tộc vào núi lấy di thể, cảnh báo sẽ có bộ lạc và động vật khác tranh cướp, rồi hét lệnh xông lên khi Toan Nghê chết trong sơn động.","anchor":"Đi, mau xông lên!"},{"importance":"normal","chuong":"@c0018","tieuDe":"Cảnh giác lùi tránh Cự Thú","text":"Tộc trưởng cảm nhận luồng khí tức nguy hiểm của Hồng Hoang Cự Thú rình mò khu vực, lệnh tộc nhân rút lui không tranh trước di thể Toan Nghê, khẳng định mạng người quan trọng nhất — nhờ vậy Thạch Thôn tránh được thảm kịch của ba thôn khác.","anchor":"Ông ấy cảm giác được một luồng khí tức nguy hiểm"},{"chuong":"@c0019","importance":"normal","tieuDe":"Can ngăn rồi rút tộc","text":"Can ngăn Thạch Hạo mạo hiểm không kịp, đành dặn dò cẩn thận rồi hạ lệnh rút cả tộc về vì vùng tranh đoạt quá nguy hiểm.","anchor":"Thạch Hạo vèo một tiếng nhảy lên cao năm sáu mét, hạ xuống lưng chim rộng rãi"},{"chuong":"@c0023","importance":"normal","tieuDe":"Dẫn Thạch Thôn cứu viện","text":"Dẫn Thạch Lâm Hổ, Thạch Phi Giao ập tới cứu Thạch Hạo, quát Bái Lý Thanh phá quy củ Đại Hoang, đổ đan giải độc cho Thanh Lân Ưng.","anchor":"Người của Thạch Thôn đã tới rồi, dẫn đầu chính là lão tộc trưởng Thạch Vân Phong"},{"importance":"normal","chuong":"@c0024","tieuDe":"Giải thích Bảo cụ, chuẩn bị đối phó Tế Linh","text":"Giải độc cho Thanh Lân Ưng, giải thích Bảo cụ do Tế Linh ban khi Tế Linh còn sống thì không cần Cốt văn cũng dùng được. Khi sinh vật kinh khủng tới gần, gọi Lâm Hổ và Phi Giao chuẩn bị giết Tế Linh Bái thôn nếu nó dám xuất hiện.","anchor":"Con mẹ nó, Tế linh Bái thôn dám xuất hiện thì chúng ta giết nó!!!"}],"tuViMoc":[{"chuong":"@c0001","canhGioi":"Phàm nhân","text":"Lão tộc trưởng phàm nhân, tinh khí thần sung túc nhờ rèn luyện và hít thở tinh khí đất trời.","importance":"minor"}],"nhanMach":[{"ten":"Chú nhóc (chưa đặt tên)","tag":"an-nhan","quanHe":"Người được chăm sóc","ghiChu":"Nấu sữa thú nuôi chú nhóc mồ côi."},{"ten":"Thạch Lâm Hổ","tag":"su-mon","quanHe":"Tộc trưởng đời sau","ghiChu":"Thủ lĩnh đội săn, người kế vị Thạch Thôn."},{"ten":"Thạch Lâm Hổ","tag":"dong-minh","quanHe":"Thủ lĩnh đội săn cùng thôn","ghiChu":"Thạch Lâm Hổ dẫn đội săn trở về báo tin cự thú và dấu chân khổng lồ cho tộc trưởng"},{"ten":"Chú nhóc (chưa đặt tên)","tag":"khac","quanHe":"Nuôi dưỡng chú nhóc mồ côi bằng sữa thú.","ghiChu":"Nấu sữa bách thú có dược thảo cho chú nhóc bú."},{"ten":"Thạch Lâm Hổ","tag":"su-mon","quanHe":"Tộc trưởng đương nhiệm và thủ lĩnh đội săn — tộc trưởng đời sau.","ghiChu":"Cùng quyết định việc đội săn vào núi."},{"ten":"Chú nhóc (chưa đặt tên)","tag":"khac","quanHe":"Người được nuôi dưỡng","ghiChu":"Nấu sữa bách thú nuôi đứa trẻ mồ côi"},{"ten":"Thạch Lâm Hổ","tag":"dong-minh","quanHe":"Thủ lĩnh đội săn dưới quyền, tộc trưởng đời sau","ghiChu":"Cùng bàn việc vào núi săn"},{"ten":"Chú nhóc Thạch Thôn","tag":"an-nhan","quanHe":"Nuôi nấng đứa trẻ mồ côi bằng sữa bách thú","ghiChu":""},{"ten":"Thạch Lâm Hổ","tag":"su-mon","quanHe":"Tộc trưởng đời sau, thủ lĩnh đội săn dưới quyền","ghiChu":""},{"ten":"Chú nhóc Thạch Thôn","tag":"ho-hang","quanHe":"Cha nuôi","ghiChu":"Nhận nuôi nhóc tỳ (bú sữa bách thú, ăn chực trăm nhà), lấy làm đối tượng nghiên cứu cốt văn tốt nhất."},{"ten":"Thạch Lâm Hổ","tag":"dong-minh","quanHe":"Thủ lĩnh đội săn của thôn","ghiChu":"Thạch Lâm Hổ về báo tin dấu chân khổng lồ; tộc trưởng dẫn mọi người đặt xác thú lên đài tế."},{"ten":"Chú nhóc Thạch Thôn","tag":"khac","quanHe":"Nấu sữa thú nuôi đứa trẻ mồ côi","ghiChu":"Chăm bẵm chú nhóc mất cha mẹ từ nửa tuổi."},{"ten":"Thạch Lâm Hổ","tag":"dong-minh","quanHe":"Thủ lĩnh đội săn, tộc trưởng đời sau","ghiChu":"Cùng bàn việc vào núi săn."},{"ten":"Chú nhóc Thạch Thôn","tag":"ho-hang","quanHe":"Nhận nuôi nhóc tỳ (bú sữa bách thú, ăn chực trăm nhà), lấy làm đối tượng nghiên cứu cốt văn tốt nhất","ghiChu":"@c0002"},{"ten":"Thạch Lâm Hổ","tag":"dong-minh","quanHe":"Tộc trưởng và thủ lĩnh đội săn cùng thôn","ghiChu":"@c0002"},{"ten":"Cậu thiếu niên thắc mắc","tag":"khac","quanHe":"Dân làng nhỏ tuổi","ghiChu":"Vỗ vai cậu nhóc nhẫn nại giải thích nhận được tâm ý là tốt rồi khi cậu thắc mắc về Tế Linh."},{"ten":"Nhóc tỳ","tag":"khac","quanHe":"Chăm sóc, chế tắm thuốc và bảo dược đặc biệt bồi dưỡng nhóc tỳ","ghiChu":"Có chủ đích bồi dưỡng lâu dài"},{"ten":"Nhóc tỳ","tag":"an-nhan","quanHe":"Đứa trẻ được lão chăm sóc đặc biệt, nấu bảo dược riêng","ghiChu":"Đặt kỳ vọng đặc biệt vào nó"},{"ten":"Thạch Lâm Hổ","tag":"su-mon","quanHe":"Tộc lão thuộc quyền, được lệnh tế Tổ Khí đẩy lui hung cầm"},{"ten":"Thạch Hạo","tag":"khac","quanHe":"Nhóc tỳ trong thôn được cứu khỏi hung cầm"},{"ten":"Bái Lý Thanh","tag":"doi-thu","quanHe":"Đối thủ, quát vì phá quy củ Đại Hoang","ghiChu":"@c0023"},{"ten":"Thanh Lân Ưng","tag":"khac","quanHe":"Giải độc cứu hung cầm của tộc","ghiChu":"@c0023"}],"tuiDo":{}},"uuTien":80,"nguon":["@c0001","@c0002","@c0003","@c0004","@c0006","@c0009","@c0010","@c0011","@c0012","@c0013","@c0016","@c0017","@c0018","@c0019","@c0023","@c0024"]},{"id":"thach-lam-ho","name":"Thạch Lâm Hổ","cn":"","aliases":["Lâm Hổ thúc","Lâm Hổ"],"gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (@c0001)","trangThai":"song","blurb":"Thủ lĩnh đội săn, tộc trưởng đời sau của Thạch Thôn, cao hơn hai mét, lưng đeo đại kiếm nặng hơn ba trăm cân.","vaiTro":"Thủ lĩnh đội săn kiêm tộc trưởng kế vị, gánh việc kiếm thức ăn cho thôn bằng săn bắn.","tinhCach":[{"text":"Dũng mãnh, quyết đoán, sẵn sàng dẫn người vào núi nguy hiểm để cứu đói.","chuong":"@c0001"}],"tabs":{"diem":[{"text":"Thân hình cao hơn hai mét, da màu đồng cơ bắp cuồn cuộn, sức mạnh hơn người.","chuong":"@c0001"},{"text":"Tộc trưởng đời sau, lãnh đạo đội săn Thạch Thôn.","chuong":"@c0001"}],"kinhLich":[{"text":"Thạch Lâm Hổ báo thức ăn sắp cạn và đề nghị dẫn người vào núi săn bắn ban ngày; ý kiến được mọi người tán thành.","anchor":"Nhưng thực sự sắp hết thức ăn rồi.","bridge":true,"khoang":"@c0001"},{"importance":"normal","chuong":"@c0001","tieuDe":"Xin dẫn đội săn vào núi","text":"Thạch Lâm Hổ báo thôn sắp hết thức ăn, thuyết phục dẫn người vào núi săn vì ban ngày không có điều bất thường dù về đêm núi không yên ổn. Cuối cùng mấy chục thanh niên tụ ở đầu thôn để chuẩn bị xuất phát.","anchor":"Nhưng thực sự sắp hết thức ăn rồi."},{"importance":"normal","chuong":"@c0001","tieuDe":"Đề nghị vào núi săn","text":"Thạch Lâm Hổ báo sắp hết thức ăn và đề nghị dẫn người vào núi săn ban ngày, lúc không có điều khác thường.","anchor":"Nhưng thực sự sắp hết thức ăn rồi"},{"importance":"normal","chuong":"@c0001","tieuDe":"Đề nghị dẫn người vào núi săn","text":"Thạch Lâm Hổ — thủ lĩnh đội săn, tộc trưởng đời sau, thân cao hơn hai mét, lưng đeo đại kiếm nặng hơn ba trăm cân — báo thức ăn sắp hết và đề nghị dẫn người vào núi săn ban ngày lúc không có điều khác thường.","anchor":"Nhưng thực sự sắp hết thức ăn rồi"},{"importance":"normal","chuong":"@c0001","tieuDe":"Đề nghị vào núi săn","text":"Thủ lĩnh đội săn, tộc trưởng đời sau của Thạch Thôn, thân cao hơn hai mét lưng đeo đại kiếm nặng hơn ba trăm cân, báo sắp hết thức ăn và đề nghị dẫn người vào núi săn ban ngày lúc không có điều khác thường.","anchor":"Nhưng thực sự sắp hết thức ăn rồi"},{"text":"Chiều tà, Thạch Lâm Hổ dẫn đội săn trở về, gần như ai cũng kéo theo một con mãnh thú khổng lồ mà không ai bị thương; lão giải thích mấy đêm trong núi có cự thú siêu cấp đi qua dẫm thương vô số thú rừng nên đoàn lần theo giết hung thú trọng thương, đồng thời báo tin thấy dấu chân lớn giống chân người dài gần trăm mét.","anchor":"Trong núi có mấy dấu chân lớn hình dạng giống chân người, nhưng thực sự quá lớn, dài đến gần trăm mét!","bridge":true,"khoang":"@c0002"},{"importance":"normal","chuong":"@c0002","tieuDe":"Báo tin dấu chân khổng lồ","text":"Lâm Hổ báo trong núi có mấy dấu chân lớn hình dạng giống chân người dài gần trăm mét, khiến dân làng và bô lão thót dạ, càng chắc chắn sâu trong núi đã phát sinh chuyện bất thường.","anchor":"Trong núi có mấy dấu chân lớn hình dạng giống chân người, nhưng thực sự quá lớn, dài đến gần trăm mét!"},{"importance":"normal","chuong":"@c0002","tieuDe":"Dẫn đội săn thắng lớn trở về","text":"Chiều tà, lão dẫn mấy chục người đội săn trở về, gần như ai cũng kéo theo một con mãnh thú khổng lồ (voi sừng rồng, Quỳ Thú, Phi Mãng, Hỏa Tê, Tì Hưu…) mà không ai bị thương.","anchor":"Chuyến này thực sự vô cùng may mắn, cả đoàn ai cũng đầy túi trở về mà không ai bị thương"},{"importance":"normal","chuong":"@c0002","tieuDe":"Báo tin dấu chân khổng lồ","text":"Lão giải thích mấy đêm qua trong núi có cự thú siêu cấp đi qua dẫm thương vô số thú rừng, và phát hiện dấu chân lớn hình dạng giống chân người dài gần trăm mét.","anchor":"Trong núi có mấy dấu chân lớn hình dạng giống chân người, nhưng thực sự quá lớn, dài đến gần trăm mét!"},{"importance":"normal","chuong":"@c0006","tieuDe":"Xác nhận sức mạnh thuần túy của Thạch Hạo","text":"Thủ lĩnh đội săn Thạch Lâm Hổ khẳng định việc Thạch Hạo nhấc đỉnh ngàn cân là sức mạnh cơ thể thuần túy, không phải cốt văn; sau khi đội săn về, ông hái Tương Quả tặng Thạch Hạo.","anchor":"đây là sức mạnh cơ thể thuần túy"},{"importance":"minor","chuong":"@c0008","tieuDe":"Được nhắc là người lớn trong thôn","text":"Được nhắc tới cùng tộc trưởng như người lớn có uy tín trong Thạch Thôn; bọn trẻ kỳ vọng sẽ được nhìn nhận khác sau vụ trộm trứng, nhưng bản thân chưa ra mặt.","anchor":"Thôn làng ở ngay phía trước không xa, mau xông lên!"},{"chuong":"@c0009","importance":"normal","tieuDe":"Tế Tổ Khí đẩy lui hung cầm","text":"Trong đội cứu viện, Thạch Lâm Hổ lấy ra cục xương tay hung thú làm Tổ Khí, tay trái nổi cốt văn rồi ấn cục xương lên, phát luồng hơi thở như vua vạn thú sống lại khiến Thanh Lân Ưng chấn động bay lên xa; cục xương dung hợp vào cánh tay trái, ngưng thành phù hiệu cổ xưa.","anchor":"như thể vua của vạn thú sống lại khiến cho con hung cầm ở trên không chấn động"},{"importance":"normal","chuong":"@c0010","tieuDe":"Dung hợp Tổ Khí thứ nhất","text":"Dung hợp xương cánh tay hung thú cổ đại vào xương tay mình, thân cao vọt từ hai mét lên ba mét, huyết khí kinh người, bức lui Thanh Lân Ưng.","anchor":"chiều cao từ hai mét tăng lên ba mét một cách khó tin"},{"importance":"normal","chuong":"@c0011","tieuDe":"Bàn giữ trứng, giao việc ấp","text":"Hỏi tộc trưởng có giữ ba quả trứng không, sau khi Thanh Lân Ưng tặng lại thì giao việc ấp và nuôi ba con chim non cho đám nhóc trong thôn.","anchor":"Thôi, trả trứng lại cho con chim không lông kia đi."},{"importance":"normal","chuong":"@c0012","tieuDe":"Báo tin cha Bì Hầu bị thương","text":"Đi trong đội săn, sắc mặt không tốt khi báo tin cha Bì Hầu bị người Bái Thôn bắn một mũi tên trúng lá phổi.","anchor":"cha Bì Hầu bị thương không nhẹ, bị người ta bắn một mũi tên, bị thương lá phổi"},{"importance":"normal","chuong":"@c0013","tieuDe":"Tố cáo Bái Thôn, triệu tập vận thú","text":"Xử lý sơ vết thương cho Thạch Thủ Sơn, tố cáo người Bái Thôn vượt giới cướp con Lục Túc Đà và ra tay tàn nhẫn. Triệu tập tộc nhân đi vận chuyển bãi xác dị thú; phẫn nộ khi bị Bái Thôn chặn cướp. Là một trong hai người trong thôn có thể bắn xuyên giáp ba lớp như thằng nhóc Bái Thôn.","anchor":"vượt giới tới chỗ chúng ta để cướp một con Lục Túc Đà do Thủ Sơn bắn chết"},{"importance":"normal","chuong":"@c0014","tieuDe":"Đấu tiễn ngang tài với thiếu niên Bái Thôn","text":"Dẫn đầu dân Thạch Thôn truy đuổi Bái Thôn cướp vật săn, phát hiện hố bẫy cắm dùi sắt. Bị thiếu niên Bái Thôn bắn mũi tên lạnh cứa rách da cổ, Thạch Lâm Hổ giương cung sừng rồng bắn trả, hai bên đấu liên tiếp mười mấy mũi tên va chạm không phân cao thấp. Khi thiếu niên bắn bốn mũi nhắm Thạch Hạo, y cứu được ba mũi, mũi thứ tư do Thạch Hạo tự chém hất.","anchor":"mũi tên sắt cứa qua cổ y kéo theo một tia máu phun dài"},{"importance":"normal","chuong":"@c0016","tieuDe":"Đàm phán ép Bái Thôn bồi thường","text":"Hán tử cao gần hai mét rưỡi chỉ huy phe Thạch Thôn, nhắc tội cướp con mồi và chặn giết tộc nhân của Bái Thôn, ra lệnh dọa chặt đầu Bái Phong buộc đối phương giao toàn bộ vũ khí và rút khỏi vùng núi.","anchor":"chặt đầu thằng oắt này xuống trả lại Bái Thôn cho ta"},{"importance":"normal","chuong":"@c0017","tieuDe":"Bàn về Thái Cổ Di Chủng và Bảo Thuật","text":"Thanh niên trai tráng trong tộc, hô hấp dồn dập khi bàn về di thể Toan Nghê, nói về Thái Cổ Di Chủng chân chính và Bảo Thuật kinh người của các chủng tộc lớn.","anchor":"tộc chúng ta coi như cũng có một môn Bảo Thuật rồi"},{"importance":"normal","chuong":"@c0018","tieuDe":"Trọng thương trước Cự Bưu","text":"Sốt ruột dẫn đầu vào núi tranh di thể Toan Nghê; khi hai con Bưu tấn công, vung kiếm bản to xông tới nhưng bị đánh bay vũ khí, rách bụng trọng thương. Sau đó an ủi Thạch Hạo khi nó lần đầu giết thú.","anchor":"Lại là loài Bưu đáng sợ, hơn nữa còn những hai con!"},{"chuong":"@c0019","importance":"normal","tieuDe":"Nhắc nhở Thạch Hạo cẩn thận","text":"A thúc của Thạch Thôn, cùng tộc trưởng can ngăn Thạch Hạo, nhắc nhở cẩn thận khi nhóc tỳ cưỡi Thanh Lân Ưng ra trận.","anchor":"Thạch Hạo vèo một tiếng nhảy lên cao năm sáu mét, hạ xuống lưng chim rộng rãi"},{"chuong":"@c0023","importance":"normal","tieuDe":"Theo cứu viện Thạch Hạo","text":"Theo Thạch Vân Phong tới cứu viện, rống chửi người Bái Thôn tạp chủng, tham gia hỗn chiến.","anchor":"Người của Thạch Thôn đã tới rồi, dẫn đầu chính là lão tộc trưởng Thạch Vân Phong"}],"tuViMoc":[{"chuong":"@c0001","canhGioi":"Phàm nhân","text":"Tráng sĩ phàm nhân thể chất cường tráng, mang đại kiếm nặng hơn ba trăm cân.","importance":"minor"}],"nhanMach":[{"ten":"Thạch Vân Phong","tag":"su-mon","quanHe":"Lão tộc trưởng","ghiChu":"Bậc đứng đầu thôn, người tiền nhiệm."},{"ten":"Thạch Vân Phong","tag":"dong-minh","quanHe":"Tộc trưởng Thạch Thôn","ghiChu":"Báo tin cự thú và dấu chân khổng lồ cho tộc trưởng"},{"ten":"Thạch Vân Phong","tag":"su-mon","quanHe":"Tộc trưởng đương nhiệm — Thạch Lâm Hổ là tộc trưởng đời sau.","ghiChu":"Cùng quyết định việc đội săn vào núi."},{"ten":"Thạch Vân Phong","tag":"su-mon","quanHe":"Lão tộc trưởng dẫn dắt; ông là tộc trưởng đời sau kế nhiệm","ghiChu":""},{"ten":"Thạch Vân Phong","tag":"dong-minh","quanHe":"Tộc trưởng của thôn","ghiChu":"Báo tin cho tộc trưởng; tộc trưởng dẫn mọi người đặt xác thú lên đài tế."},{"ten":"Thạch Vân Phong","tag":"dong-minh","quanHe":"Lão tộc trưởng Thạch Thôn","ghiChu":"Cùng bàn việc vào núi săn."},{"ten":"Thạch Hạo","tag":"an-nhan","quanHe":"Tặng Thạch Hạo túi Tương Quả","ghiChu":"@c0006"},{"ten":"Thạch Vân Phong","tag":"su-mon","quanHe":"Tộc trưởng ra lệnh cứu viện, cùng chỉ huy phòng thủ và tế Tổ Khí"},{"ten":"Bì Hầu","tag":"khac","quanHe":"Nhớ ra bọn Bì Hầu từng thò đầu nghe chuyện, lần ra manh mối đám nhóc"},{"ten":"Thiếu niên Bái Thôn","tag":"doi-thu","quanHe":"Địch thủ đấu tiễn ngang tài"},{"ten":"Bái Phong","tag":"doi-thu","quanHe":"Ngồi lên người, dọa chặt đầu để ép bồi thường","ghiChu":""},{"ten":"Bái Lý Thanh","tag":"doi-thu","quanHe":"Đối thủ trong trận hỗn chiến Bái Thôn","ghiChu":"@c0023"}],"tuiDo":{"phapBao":[{"ten":"Đại kiếm kim loại đen","loai":"vũ khí","trangThai":"dang-co","moTa":"Đại kiếm rèn từ kim loại màu đen nặng hơn ba trăm cân, đeo sau lưng.","nguon":"@c0001"}]}},"uuTien":70,"nguon":["@c0001","@c0002","@c0006","@c0008","@c0009","@c0010","@c0011","@c0012","@c0013","@c0014","@c0016","@c0017","@c0018","@c0019","@c0023"]},{"id":"nguoi-trung-nien-day-tre","name":"Người đàn ông trung niên dạy lũ trẻ (chưa đặt tên)","cn":"","aliases":[],"gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (@c0001)","trangThai":"song","blurb":"Người đàn ông trung niên tráng kiện như hổ báo, chỉ điểm lũ trẻ rèn luyện thân thể buổi sớm.","vaiTro":"Người kèm cặp, hướng dẫn lũ trẻ Thạch Thôn luyện thể dưới mây sớm.","tinhCach":[{"text":"Tận tâm chỉ dạy, am hiểu phương pháp rèn luyện thân thể.","chuong":"@c0001"}],"tabs":{"diem":[{"text":"Mặc áo da thú, nước da đồng, tóc đen buông xõa, tráng kiện như hổ báo.","chuong":"@c0001"}],"kinhLich":[{"text":"Đứng chỉ điểm và giảng cho lũ trẻ rằng lúc mặt trời mới mọc sinh khí mạnh nhất, rèn luyện dưới mây sớm giúp bồi đắp sinh cơ, cường gân tráng cốt.","anchor":"rèn luyện thân thể dưới làn mây sớm cũng có ích lợi rất lớn","bridge":true,"khoang":"@c0001"},{"importance":"minor","chuong":"@c0001","tieuDe":"Chỉ dạy lũ trẻ rèn luyện buổi sớm","text":"Buổi sáng, ông chỉ điểm đám trẻ trên khoảng đất trống trước thôn, giảng rằng lúc mặt trời mới mọc sinh khí mạnh nhất, rèn luyện thân thể dưới mây sớm có thể bồi đắp sinh cơ, cường gân tráng cốt — vốn liếng sinh tồn trong mãng sơn.","anchor":"rèn luyện thân thể dưới làn mây sớm cũng có ích lợi rất lớn"},{"importance":"normal","chuong":"@c0001","tieuDe":"Dạy lũ trẻ rèn luyện sáng sớm","text":"Người trung niên chỉ dạy đám trẻ rèn luyện thân thể dưới mây sớm, giảng rằng lúc mặt trời mới mọc sinh khí mạnh nhất giúp bồi đắp sinh cơ để có vốn sinh tồn trong mãng sơn.","anchor":"Lúc mặt trời mới mọc là lúc vạn vật khởi đầu, sinh khí mạnh nhất"}],"tuViMoc":[{"chuong":"@c0001","canhGioi":"Phàm nhân","text":"Người trung niên phàm nhân thể chất cường tráng của Thạch Thôn.","importance":"minor"}],"nhanMach":[],"tuiDo":{}},"uuTien":30,"nguon":["@c0001"]},{"id":"chu-nhoc-thach-thon","name":"Chú nhóc Thạch Thôn","cn":"","aliases":["Chú nhóc","Đứa trẻ mồ côi","Nhóc tỳ","Đứa trẻ mồ côi Thạch Thôn"],"gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (@c0001)","trangThai":"song","blurb":"Đứa trẻ khoảng một tuổi rưỡi mồ côi cha mẹ từ nửa tuổi, bú sữa bách thú lớn lên ở Thạch Thôn, đáng yêu và hiếu động.","vaiTro":"Nhân vật trung tâm được khắc họa kỹ ở chương mở đầu; mồ côi cha mẹ, được lão tộc trưởng nuôi bằng sữa bách thú trộn dược thảo.","tinhCach":[{"text":"Hiếu động, dạn dĩ, bám theo đám trẻ lớn rèn luyện dù mới biết đi","chuong":"@c0001"},{"text":"Bướng bỉnh kiên cường — ngã liên tục mà không khóc, tức tối bò dậy đuổi tiếp","chuong":"@c0001"}],"tabs":{"diem":[{"text":"Đáng yêu như búp bê sứ, đôi mắt đen láy, khiến cả thôn bật cười","chuong":"@c0001"},{"text":"Mồ côi cha mẹ từ nửa tuổi, bú sữa bách thú lớn lên, vẫn chưa cai sữa","chuong":"@c0001"}],"kinhLich":[{"text":"Chú nhóc một tuổi rưỡi mồ côi cha mẹ từ nửa tuổi, được lão tộc trưởng Thạch Vân Phong nấu sữa bách thú trộn dược thảo nuôi lớn; bám theo đám trẻ rèn luyện buổi sớm rồi đuổi theo con chim sẻ năm màu, ngã liên tục mà không khóc.","anchor":"Chú nhóc mất cha mẹ từ khi mới nửa tuổi, bú sữa bách thú lớn lên","bridge":true,"khoang":"@c0001"},{"importance":"normal","chuong":"@c0001","tieuDe":"Bám theo lũ trẻ rèn luyện","text":"Chú nhóc một tuổi rưỡi mới biết đi tự trà trộn vào đám trẻ rèn luyện dưới mây sớm, rồi đuổi theo con chim sẻ năm màu, vấp ngã liên tục mà không khóc.","anchor":"nó không khóc mà tức tối lồm cồm bò dậy tiếp tục đuổi theo"},{"importance":"normal","chuong":"@c0001","tieuDe":"Đứa trẻ mồ côi nuôi bằng sữa bách thú","text":"Lão tộc trưởng Thạch Vân Phong nấu sữa thú trộn dược thảo nuôi chú nhóc; đứa trẻ mất cha mẹ từ nửa tuổi, bú sữa bách thú lớn lên, nay vẫn chưa cai sữa và bị đám trẻ lớn trêu chọc.","anchor":"Chú nhóc mất cha mẹ từ khi mới nửa tuổi, bú sữa bách thú lớn lên"},{"text":"Theo yêu cầu lũ trẻ, nhóc tỳ giơ hai bàn tay dùng sức, một ký tự kỳ lạ như đúc kim loại nổi lên cả hai lòng bàn tay, nhấc bổng khối đá xanh cao hơn người mình khiến lũ trẻ kinh ngạc.","anchor":"lòng bàn tay nó xuất hiện một quầng sáng, một kí tự kì lạ nổi lên","bridge":true,"khoang":"@c0002"}],"tuViMoc":[{"chuong":"@c0001","canhGioi":"Phàm nhân","text":"Đứa trẻ một tuổi rưỡi bình thường, mới biết đi chưa lâu, được nuôi bằng sữa bách thú.","importance":"minor"}],"tuVi":"","nhanMach":[{"ten":"Thạch Vân Phong","tag":"an-nhan","quanHe":"Lão tộc trưởng nuôi nấng, nấu sữa bách thú chăm sóc","ghiChu":"Cha mẹ chú nhóc đã mất từ khi nó nửa tuổi"},{"ten":"Thạch Vân Phong","tag":"ho-hang","quanHe":"Cha nuôi","ghiChu":"Được Thạch Vân Phong nhận nuôi và chọn làm đối tượng nghiên cứu cốt văn tốt nhất."},{"ten":"Thạch Vân Phong","tag":"an-nhan","quanHe":"Lão tộc trưởng nấu sữa thú trộn dược thảo nuôi nấng","ghiChu":"Chăm bẵm đứa trẻ mồ côi từ nửa tuổi."},{"ten":"Thạch Vân Phong","tag":"ho-hang","quanHe":"Được tộc trưởng nhận nuôi và lấy làm đối tượng nghiên cứu cốt văn","ghiChu":"@c0002"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[{"ten":"Sữa bách thú","loai":"thực phẩm/dưỡng chất","trangThai":"dang-co","moTa":"Sữa thú nấu trộn dược thảo trong ang gốm, nuôi chú nhóc mồ côi lớn lên.","nguon":"@c0001"}]}},"uuTien":90,"nguon":["@c0001","@c0002"]},{"id":"cau-thieu-nien-thac-mac","name":"Cậu thiếu niên thắc mắc","gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Một thiếu niên Thạch Thôn hay thắc mắc về tục cúng tế Tế Linh.","tabs":{"diem":[{"text":"Tính tò mò, hay thắc mắc nhưng thật ra vẫn thành tâm","chuong":"@c0003"}],"kinhLich":[{"text":"Làu bàu hỏi vì sao nhiều năm qua Tế Linh chưa từng đụng đến cống phẩm mà vẫn phải cúng tế; bị cha định đánh, được lão tộc trưởng xua tay ngăn; mặt đỏ bừng phân trần không phải mình không thành tâm.","anchor":"Tế Linh là Linh mà chúng ta cúng tế và phụng dưỡng, quý ở tấm lòng thành","bridge":true,"khoang":"@c0003"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Vân Phong","tag":"khac","quanHe":"Tộc trưởng thôn","ghiChu":"Được lão tộc trưởng vỗ vai nhẫn nại giải thích Tế Linh quý ở tấm lòng thành."}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0003"]},{"id":"nhoc-ty","name":"Nhóc tỳ","cn":"","aliases":["chú nhóc","chú bé","Thạch Hạo","Chú nhóc","Nhóc tỳ","Tiểu Hạo Hạo","Tiểu Thạch Hạo","nhóc tỳ"],"gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân — luyện thể (@c0004)","trangThai":"song","blurb":"Đứa bé được Thạch Vân Phong chăm sóc đặc biệt trong Thạch Thôn, thể chất phi thường và mang cốt văn thần bí.","vaiTro":"Nhân vật trung tâm của Thạch Thôn, được bồi dưỡng đặc biệt qua tắm thuốc và bảo dược.","tinhCach":[{"text":"Ngoan ngoãn, chịu đựng tốt nước thuốc cực mạnh mà không khóc","chuong":"@c0004"},{"text":"Khi dược kình phát tác thì nổi cơn quậy phá khắp thôn","chuong":"@c0004"}],"tabs":{"diem":[{"text":"Thể chất khác thường, chịu được nước thuốc cực mạnh mà trẻ khác không chịu nổi","chuong":"@c0004"},{"text":"Mang cốt văn thần bí tự vận chuyển luyện hóa dược lực, lan từ lòng bàn tay lên cả cánh tay","chuong":"@c0004"}],"kinhLich":[{"importance":"normal","chuong":"@c0004","tieuDe":"Tắm hắc đỉnh đặc biệt","text":"Nhóc tỳ được tắm thuốc một mình trong hắc đỉnh đặc biệt chỉ thêm chút nước trắng, còn lại toàn chân huyết và bột xương hung thú; tộc trưởng đập tan Tỳ Hưu và tê giác hai đầu phóng từ hai bình thành huyết dịch rơi vào đỉnh. Nhờ thể chất cực mạnh và cốt văn tự vận chuyển luyện hóa dược lực, nó chịu được, uống no thuốc rồi ngủ say trong lòng Thạch Vân Phong.","anchor":"thân hình nhỏ bé ngã vào trong lòng Thạch Vân Phong"},{"importance":"normal","chuong":"@c0004","tieuDe":"Ăn bảo dược, cốt văn lan cánh tay","text":"Sau khi ăn ngấu nghiến hết nồi bảo dược riêng do Thạch Vân Phong nấu, dược kình quá mạnh khiến nhóc tỳ hai mắt đỏ au như mắt thỏ, quậy phá khắp thôn hai canh giờ: túm đuôi chó vàng, nhổ hàng rào, dỡ ngói. Cốt văn lan tỏa lên cả cánh tay lập lòe, thể chất-tốc độ-sức mạnh tăng nhiều, rồi gãi đầu thỏ thẻ rằng đã gây họa.","anchor":"cả cánh tay nổi cốt văn lập lòe không cố định, vô cùng thần bí"},{"importance":"normal","chuong":"@c0005","tieuDe":"Có tên riêng Thạch Hạo","text":"Sau hai năm, nhóc tỳ nay ba tuổi rưỡi và chính thức mang cái tên riêng của mình là Thạch Hạo, thể chất khỏe kinh người.","anchor":"mới đó đã hai năm trôi qua, nhóc tỳ đã ba tuổi rưỡi, có cái tên riêng thuộc về mình – Thạch Hạo"},{"importance":"major","chuong":"@c0005","tieuDe":"Nâng bổng đỉnh đồng ngàn cân","text":"Trong cuộc thi nâng đỉnh, vì thấp không với tới quai đỉnh, Thạch Hạo ngồi sụp nâng đáy chiếc đỉnh đồng ngàn cân, nhấc bổng qua chỏm đầu khiến cả thôn sững sờ, ví nó như Kim Sí Đại Bằng, con cháu Tỳ Hưu Vương thuần huyết, hung thú non Thái Cổ.","anchor":"nhấc bổng đỉnh đồng lên khỏi mặt đất, đỉnh bị nó nhấc lên quá chỏm đầu"},{"importance":"normal","chuong":"@c0006","tieuDe":"Ném đỉnh ngàn cân chấn động dân làng","text":"Ba tuổi, Thạch Hạo nhấc bổng chiếc đỉnh đồng nặng ngàn cân rồi ném xuống đất, khiến cả Thạch Thôn sững sờ; thủ lĩnh đội săn xác nhận đó là sức mạnh cơ thể thuần túy chứ không phải cốt văn. Sau đó cậu nhận túi Tương Quả từ Thạch Lâm Hổ và khuyên tộc trưởng nghỉ ngơi.","anchor":"đây là sức mạnh cơ thể thuần túy"},{"importance":"normal","chuong":"@c0007","tieuDe":"Trèo vách lấy trứng hung cầm","text":"Đã nâng được đỉnh đồng nên thành phần tử nòng cốt của đám trẻ. Cùng đoàn lẻn vào rừng nguyên thủy tìm sào huyệt Thanh Lân Ưng, ném đá thăm dò rồi trèo vách đá cao khoảng 300 mét lên trước, phát hiện ba quả trứng dị cầm trong Ngô Sào.","anchor":"giống như một con khỉ con, vèo một tiếng nhanh chóng trèo thoăn thoắt lên dốc đá"},{"importance":"normal","chuong":"@c0008","tieuDe":"Nhận diện huyết mạch Thái Cổ Ma Cầm","text":"Nhờ hằng ngày học cốt văn, Thạch Hạo nhận ra Thanh Lân Ưng là hậu duệ Thái Cổ Ma Cầm, huyết mạch còn mảnh vụn phù văn truyền thừa; đồng thời thu mấy tấm vảy hung cầm sắc lẻm trong tổ.","anchor":"Đây chính là vảy hung cầm trưởng thành, quả nhiên bất phàm"},{"chuong":"@c0009","importance":"normal","tieuDe":"Trốn hung cầm vào thạch động","text":"Bị Thanh Lân Ưng truy sát, Thạch Hạo dẫn cả bọn chui vào một thạch động ẩm ướt ẩn sau bụi dây leo (nơi cậu tìm ra khi trước đuổi theo con chim tước đỏ như máu giống Chu Tước), chạy sâu mấy chục mét để né.","anchor":"Ở bên này có một cái thạch động rất sâu, chúng ta vào trong né cái đã!"},{"chuong":"@c0009","importance":"normal","tieuDe":"Ném thiết mâu thương hung cầm","text":"Thạch Hạo mượn thiết mâu nặng bốn năm chục cân, lấy đà ném về mắt Thanh Lân Ưng khiến nó lần đầu lộ vẻ kinh dị, làm bong một miếng vẩy ở khóe mắt và chảy máu; sau đó đề xuất chọc giận nó tạo động tĩnh để câu giờ chờ cứu viện.","anchor":"ở khóe mắt con hung cầm này cũng đã bong mất một miếng vẩy"},{"importance":"normal","chuong":"@c0010","tieuDe":"Kể chuyện Tiểu Hồng, đề nghị trả trứng","text":"Bé ba tuổi rưỡi, không bị phạt đòn còn được uống sữa thú vì kể cho tộc trưởng chuyện Tiểu Hồng — con chim sẻ đỏ rực (Chu Tước truyền thuyết) từng đuổi bắt; đề nghị trả ba quả trứng cho Thanh Lân Ưng.","anchor":"Tiểu Hồng chính là con chim sẻ toàn thân đỏ rực đó."},{"importance":"normal","chuong":"@c0012","tieuDe":"Dạy cốt văn cho ba chim non","text":"Thạch Hạo dạy ba con Thanh Lân Ưng cốt văn của loài người; Tử Vân học cực hăng, ngày càng thân với nó. Nó cũng trổ tài phù văn bắn chim sẻ đỏ đốt cháy đại thụ.","anchor":"Lão đại tên là Đại Bằng, lão nhị Tiểu Thanh, lão tam Tử Vân."},{"importance":"major","chuong":"@c0012","tieuDe":"Lĩnh ngộ Bí Cốt Bảo Thư","text":"Thạch Hạo nghiên cứu và đối chiếu phù văn của ba chim non rồi ngộ ra, thi triển bảo phù: phóng vầng trăng khuyết chém đứt đại thụ, phóng vầng trăng sáng chém đôi tảng đá cao năm sáu mét. Tộc trưởng kinh động khen thiên tư.","anchor":"khối đá lớn trong nháy mắt bị chia thành hai nửa"},{"importance":"normal","chuong":"@c0013","tieuDe":"Thăm Thủ Sơn, theo đại đội báo thù","text":"Mang một rổ quả mọng đỏ tới thăm Thạch Thủ Sơn trọng thương, sau đó hưng phấn đòi đi lấy chân huyết hung thú, dặn Đại Bằng, Tiểu Thanh, Tử Vân ở nhà chờ. Cuối chương an ủi A Phúc thúc bị thương trong vụ chặn cướp rồi đuổi theo đại đội nhân mã vào rừng.","anchor":"đại đội nhân mã ở phía trước."},{"importance":"normal","chuong":"@c0014","tieuDe":"Chém hất mũi tên, lộ kí tự bí ẩn","text":"Trong trận hỗn chiến với Bái Thôn, khi thiếu niên Bái Thôn bắn liền bốn mũi tên nhắm nhóc tỳ, Thạch Lâm Hổ chỉ phá được ba mũi. Thạch Hạo chưa đầy 4 tuổi dùng tay trái chém lên thân mũi tên còn lại hất văng đi, trong lòng bàn tay trái lóe lên một kí tự bí ẩn rồi nhanh chóng lụi đi, chỉ số ít người thấy. Sau đó nó nhảy lao thẳng tới thiếu niên Bái Thôn.","anchor":"tay trái của nhóc tỳ chém lên thân mũi tên, hất văng mũi tên ra"},{"importance":"normal","chuong":"@c0015","tieuDe":"Đánh bại thiếu niên Bái Phong","text":"Thạch Hạo — đứa bé chưa đến bốn tuổi — đấu tay đôi với thiếu niên Bái Phong mười bốn tuổi thần lực kinh người. Nó né tám mũi tên sắt, dùng sức mạnh Cốt Văn/văn lạc chém đứt trường mâu Huyết Văn Thiết, tạo vầng trăng lưỡi liềm phá tan tên nỏ, cuối cùng đánh Bái Phong phun máu bay ngang rồi đuổi theo.","anchor":"Bái Phong phun ra một bụm máu tươi, người bay ngang ra"},{"importance":"normal","chuong":"@c0016","tieuDe":"Đá gục và bắt sống Bái Phong","text":"Nhóc tỳ hơn ba tuổi rưỡi liều mạng xông lên, đá một cước vào ngực khiến Bái Phong ngã ngửa, rồi nắm cổ áo nhấc lên làm lá chắn và dùng tay tỏa ánh sáng đánh trọng thương hắn, cuối cùng bắt sống ném về phe Thạch Thôn.","anchor":"nhấc hắn lên che ở trước người"},{"importance":"major","chuong":"@c0017","tieuDe":"Nắm giữ Bảo Thuật vầng trăng bạc","text":"Nhóc tỳ nghiên cứu Nguyên Thủy Bảo Phù, triệu ra vầng trăng bạc hoàn chỉnh treo sau đầu, trong đó có cung điện và gốc cây, bay ra cắt đứt liền ba tảng đá lớn (lần trước chỉ một). Tộc trưởng và tộc lão xác nhận đây là một môn Bảo Thuật — thần thông mà các bộ tộc lớn quý trọng giữ kín, lần đầu tiên Thạch tộc có được.","anchor":"lần này lại có thể trực tiếp cắt đứt ba tảng đá, thật là lợi hại!"},{"importance":"normal","chuong":"@c0017","tieuDe":"Xin theo tộc lấy di thể Toan Nghê","text":"Toan Nghê chết già trong sơn động, di thể là kho báu với chân huyết dùng cho lễ tẩy. Nhóc tỳ xin đi cùng và được tộc trưởng chấp nhận vì đã nắm Bảo Thuật, dặn ba con chim non ở lại tiếp tục khuyên Thanh Lân Ưng đến giúp.","anchor":"chúng ta phải bắt đầu hành động rồi"},{"importance":"normal","chuong":"@c0018","tieuDe":"Lần đầu giết mãnh thú","text":"Khi Thạch Lâm Hổ và Thạch Phi Giao bị hai con Bưu dữ đánh trọng thương, Thạch Hạo tức giận dùng Bảo Thuật của Thanh Lân Ưng tạo vầng trăng bạc, chặt chân rồi chém đầu cả hai con Bưu — lần đầu tiên nó giết mãnh thú, ngẩn người nhìn bàn tay mình.","anchor":"Một kích của Thạch Hạo thoáng cái đã chém chết một con Bưu dữ đáng sợ."},{"importance":"normal","chuong":"@c0018","tieuDe":"Quyết tranh bảo thể Toan Nghê","text":"Sau khi nhận ra Bảo Thuật vừa giết thú vừa cứu người, Thạch Hạo khao khát lấy được ký hiệu nguyên thủy của Toan Nghê, nhảy lên gọi Thanh Lân Ưng chở đi tranh đoạt bảo thể.","anchor":"Chúng ta cùng nhau đi tranh đoạt bảo thể của Toan Nghê."},{"chuong":"@c0019","importance":"normal","tieuDe":"Cưỡi Thanh Lân Ưng tranh đoạt","text":"Bất chấp tộc trưởng can ngăn, Thạch Hạo nhảy lên lưng Thanh Lân Ưng lao tới vùng núi tranh đoạt thi thể Toan Nghê. Dùng trăng bạc chém đứt sừng và chém đầu Sơn Miêu phục kích, hỗ trợ đối phó Tử Kim Xà và Huyết Điêu, suýt bị đâm thủng bụng.","anchor":"Thạch Hạo vèo một tiếng nhảy lên cao năm sáu mét, hạ xuống lưng chim rộng rãi"},{"importance":"normal","chuong":"@c0020","tieuDe":"Trọng thương Thử Vương","text":"Nằm trên lưng Thanh Lân Ưng, Thạch Hạo dùng vầng trăng bạc từ Cốt Văn truy kích con Thử Vương chuột tím to cỡ cối đá. Kết hợp với ký hiệu nguyên thủy của Thanh Lân Ưng, cuối cùng đánh gãy xương Thử Vương khiến nó trọng thương rơi xuống.","anchor":"xương của Thử Vương gãy một bộ phận, bị thương trầm trọng"},{"importance":"normal","chuong":"@c0021","tieuDe":"Gom đủ ba Thái Cổ Di Chủng","text":"Nhóc tỳ nhận ra Toan Nghê cố tình giả chết để dụ Ác Ma Viên và Ly Hỏa Ngưu Ma tới rồi tiêu diệt, khen loài này có trí tuệ. Sau đại chiến, nó khiêng cái sừng dài mấy mét của Ly Hỏa Ngưu Ma, cùng Thanh Lân Ưng gom đủ ba con Thái Cổ Di Chủng, vui sướng vì có đủ chân huyết cho lễ tẩy năm tuổi mà tộc trưởng và các a thúc lo lắng bấy lâu.","anchor":"vì việc tẩy lễ lúc năm tuổi của mình mà lo lắng"},{"importance":"normal","chuong":"@c0022","tieuDe":"Đánh lui phục kích Bái Thôn","text":"Bị hơn hai mươi người đội săn thú Bái Thôn phục kích bằng tên và mâu sắt gần Thạch Thôn. Thạch Hạo một mình dùng Bảo Nguyệt (trăng bạc) đánh rơi tên sắt, chém đứt vai tay đối thủ, chém rách bụng thủ lĩnh khiến chúng phải rút lui, nhưng tự trách không nỡ hạ sát.","anchor":"hai tay giương ra, vẽ ra một vầng trăng óng ánh lóa mắt"},{"importance":"normal","chuong":"@c0022","tieuDe":"Cứu chữa Thanh Lân Ưng","text":"Chém thịt dính bảo huyết trong sừng đỏ của Thái Cổ Di Chủng nhét vào mỏ Thanh Lân Ưng đang trọng thương kiệt sức, tin sừng có thể giải độc như sừng Linh Tê.","anchor":"Đây là bảo huyết trong sừng của Thái Cổ Di Chủng"},{"chuong":"@c0023","importance":"normal","tieuDe":"Thủ hộ bảo thể, chém giết mãnh thú","text":"Trời tối một mình thủ hộ bên cạnh Thanh Lân Ưng trúng độc, dùng mâu sắt và trăng bạc giết Hổ Trùng vằn, Phi Mãng và sáu bảy con quái vật kéo tới vì mùi Thái Cổ chân huyết của bảo thể Toan Nghê.","anchor":"Mới có một lúc mà Thạch Hạo đã chém sáu bảy con quái vật"},{"chuong":"@c0023","importance":"normal","tieuDe":"Phản kích chém giết người Bái Thôn","text":"Bị hơn trăm người Bái Thôn phục kích bắn mưa tên, Bái Sơn bắn xuyên tay; phẫn nộ xông lên chém giết mười bảy mười tám người Bái Thôn, nhưng chân cũng trúng tên.","anchor":"Bái Thôn liền có mười bảy mười tám người ngã ở trong vũng máu"},{"chuong":"@c0023","importance":"normal","tieuDe":"Bị Bái Phong trọng thương","text":"Bị Bái Phong dùng Bảo Cụ vòng răng thú tập kích, một đốm sáng suýt đâm xuyên yết hầu, làm rách vai; lần đầu bị trúng tên nặng trong đời.","anchor":"Không chỉ ngươi mới có Bảo Cụ, ta cũng có đây"},{"importance":"normal","chuong":"@c0024","tieuDe":"Ngộ thêm tầng Bảo thuật thắng Bái Phong","text":"Trong trận với Bái Phong, ở thời khắc then chốt nhóc tỳ ngộ thêm một tầng Nguyên thủy bảo thuật, hai trăng bạc hợp thành con ma cầm đánh Bái Phong phọt máu, khiến Bảo cụ 42 răng thú rơi rụng ảm đạm.","anchor":"Nhóc tỳ ở thời khắc then chốt may mắn hiểu thêm một tầng Bảo thuật"},{"importance":"normal","chuong":"@c0024","tieuDe":"Tàn phế Bái Phong, cướp Bảo cụ","text":"Nhóc tỳ nhảy cao đá vỡ nửa mặt Bái Phong (gãy gò má trái, gãy xương sườn, ngực bể nát), rồi dùng trăng bạc cắt đứt cả tứ chi, đoạt lấy xâu răng thú 42 cái đeo lên cổ tay mình.","anchor":"hay tay hai chân Bái Phong đều bị cắt đứt"}],"tuViMoc":[{"chuong":"@c0004","canhGioi":"Phàm nhân","text":"Qua tắm thuốc và bảo dược, thể chất, tốc độ và sức mạnh tăng mạnh; cốt văn lan từ lòng bàn tay lên cả cánh tay, song chưa đến mức thoát thai hoán cốt.","importance":"minor"}],"nhanMach":[{"ten":"Thạch Vân Phong","tag":"an-nhan","quanHe":"Được tộc trưởng chăm sóc, chế tắm thuốc và bảo dược đặc biệt","ghiChu":"Thạch Vân Phong có chủ đích bồi dưỡng nhóc tỳ lâu dài"},{"ten":"Thạch Vân Phong","tag":"an-nhan","quanHe":"Người chăm sóc, nấu bảo dược riêng và bế nó khi ngủ say","ghiChu":"Tộc trưởng dành cho nó sự chăm sóc đặc biệt hơn hẳn lũ trẻ khác"},{"ten":"Thạch Mãnh","tag":"ban-be","quanHe":"Đàn anh cùng thôn, cùng thi thố sức lực.","ghiChu":"Cùng dự cuộc nâng đỉnh @c0005"},{"ten":"Thạch Đại Tráng","tag":"ban-be","quanHe":"Thiếu niên cùng thôn, người nâng đỉnh thành công trước Thạch Hạo.","ghiChu":"@c0005"},{"ten":"Thạch Trung Hầu","tag":"ban-be","quanHe":"Đàn anh cùng thôn cùng dự thi thố.","ghiChu":"@c0005"},{"ten":"Thạch Lâm Hổ","tag":"an-nhan","quanHe":"Thủ lĩnh đội săn tặng Thạch Hạo túi Tương Quả","ghiChu":"@c0006"},{"ten":"Thạch Đại Tráng","tag":"ban-be","quanHe":"Thủ lĩnh đoàn trẻ Thạch Thôn, cùng trèo vách","ghiChu":""},{"ten":"Thạch Trung Hầu","tag":"ban-be","quanHe":"Bạn trong đoàn, dẫn đường tới rừng đá","ghiChu":""},{"ten":"Thạch Mãnh","tag":"ban-be","quanHe":"Bạn trong đoàn, sức đứng sau Thạch Hạo và Đại Tráng","ghiChu":""},{"ten":"Nhị Mãnh","tag":"ban-be","quanHe":"Bạn cùng nhóm trẻ Thạch Thôn đi trộm trứng"},{"ten":"Bì Hầu","tag":"ban-be","quanHe":"Bạn cùng nhóm trẻ Thạch Thôn đi trộm trứng"},{"ten":"Thạch Đại Tráng","tag":"ban-be","quanHe":"Bạn cùng nhóm trẻ Thạch Thôn đi trộm trứng"},{"ten":"Bì Hầu","tag":"ban-be","quanHe":"Bạn cùng trốn hung cầm trong thạch động","ghiChu":"Cùng đám nhóc Thạch Thôn né Thanh Lân Ưng"},{"ten":"Nhị Mãnh","tag":"ban-be","quanHe":"Bạn cùng ném thiết mâu vào mắt hung cầm","ghiChu":"Một trong ba đứa khỏe nhất"},{"ten":"Thạch Đại Tráng","tag":"ban-be","quanHe":"Bạn cùng câu giờ chống hung cầm","ghiChu":"Đề xuất chọc giận hung cầm tạo động tĩnh"},{"ten":"Tử Vân","tag":"dong-minh","quanHe":"Chim non thân thiết nhất","ghiChu":"Tử Vân linh tính nhất trong ba chim, cực thân với Thạch Hạo."},{"ten":"Thạch Phúc","tag":"an-nhan","quanHe":"A Phúc thúc thường hái quả mọng cho nhóc tỳ","ghiChu":"Nhóc tỳ an ủi khi A Phúc thúc bị thương."},{"ten":"Thiếu niên Bái Thôn","tag":"doi-thu","quanHe":"Địch thủ đối đầu","ghiChu":"Bị thiếu niên Bái Thôn bắn tên nhắm giết, nhóc tỳ chém hất mũi tên rồi lao tới tấn công y."},{"ten":"Bái Phong","tag":"doi-thu","quanHe":"Đối thủ giao đấu","ghiChu":"Thiếu niên Bái Thôn đấu tay đôi với Thạch Hạo, bị nó đánh bại phun máu."},{"ten":"Thạch Phi Giao","tag":"dong-minh","quanHe":"Người cùng Thạch Thôn","ghiChu":"Mắng Bái Phong ác độc khi hắn giở chiêu bẩn với Thạch Hạo."},{"ten":"Bái Phong","tag":"doi-thu","quanHe":"Đối thủ bị hạ gục và bắt sống","ghiChu":"Đá gục và bắt Bái Phong tại chiến trận ranh giới hai thôn."},{"ten":"Thanh Lân Ưng","tag":"dong-hanh","quanHe":"Cùng cưỡi ra trận tranh đoạt bảo thể Toan Nghê, phối hợp chiến đấu chống đàn cự thú","ghiChu":"@c0019"},{"ten":"Thanh Lân Ưng","tag":"dong-minh","quanHe":"Hung cầm được Thạch Hạo cứu chữa, ánh mắt nhu hòa như đối con mình","ghiChu":"@c0022"},{"ten":"Thủ lĩnh đội săn thú Bái Thôn","tag":"doi-thu","quanHe":"Kẻ cầm đầu phục kích, bị Thạch Hạo chém rách bụng","ghiChu":"@c0022"},{"ten":"Bái Lý Thanh","tag":"doi-thu","quanHe":"Kẻ thù, tộc trưởng Bái Thôn mưu cướp bảo thể và giết mình","ghiChu":"@c0023"},{"ten":"Bái Sơn","tag":"doi-thu","quanHe":"Đối thủ, bắn lén xuyên tay","ghiChu":"@c0023"},{"ten":"Bái Phong","tag":"doi-thu","quanHe":"Kẻ thù cũ, tập kích bằng Bảo Cụ","ghiChu":"@c0023"},{"ten":"Thanh Lân Ưng","tag":"dong-minh","quanHe":"Hung cầm được nhóc liều mình thủ hộ","ghiChu":"@c0023"},{"ten":"Bái Phong","tag":"doi-thu","quanHe":"Kẻ địch bị nhóc tỳ đánh bại, tàn phế và cướp Bảo cụ","ghiChu":"Đối đầu trận chiến chương 24"}],"tuiDo":{"phapBao":[],"danDuoc":[{"ten":"Bảo dược đặc biệt","loai":"đan dược","trangThai":"da-dung","moTa":"Bảo dược do Thạch Vân Phong chế từ sừng voi sừng rồng, móng vuốt Tỳ Hưu, sừng Hỏa Tê, chân huyết và sữa thú; nhóc tỳ ăn hết khiến dược kình phát tác mạnh.","nguon":"@c0004"}],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"uuTien":90,"nguon":["@c0004","@c0005","@c0006","@c0007","@c0008","@c0009","@c0010","@c0012","@c0013","@c0014","@c0015","@c0016","@c0017","@c0018","@c0019","@c0020","@c0021","@c0022","@c0023","@c0024"]},{"id":"cac-bo-lao-thach-thon","name":"Các bô lão Thạch Thôn","gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Nhóm bô lão Thạch Thôn phụ giúp chủ trì tục tắm thuốc và bàn luận về thể chất nhóc tỳ.","vaiTro":"Trưởng bối phụ tr�� trong Thạch Thôn.","tinhCach":[{"text":"Lo toan, tiết kiệm chân huyết quý, có kinh nghiệm chế thuốc","chuong":"@c0004"}],"tabs":{"diem":[],"kinhLich":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0004"]},{"id":"anh-ba","name":"Anh Ba","gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Thanh niên trong Thạch Thôn được nhắc tới như tấm gương dùng cối đá rèn luyện khí lực.","vaiTro":"Nhân vật phụ được nhắc tên.","tinhCach":[{"text":"Chăm rèn luyện khí lực","chuong":"@c0004"}],"tabs":{"diem":[],"kinhLich":[],"nhanMach":[],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0004"]},{"id":"thach-manh","name":"Thạch Mãnh","cn":"","aliases":["Nhị Mãnh"],"gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (luyện thể) @c0005","trangThai":"song","blurb":"Thiếu niên tám tuổi rưỡi của Thạch Thôn, con thứ hai trong nhà, sức vóc mạnh mẽ.","vaiTro":"Thiếu niên khỏe mạnh trong đám trẻ Thạch Thôn.","tinhCach":[{"text":"Hiếu thắng, ganh đua sức lực với bạn bè.","chuong":"@c0005"}],"tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0005","tieuDe":"Vật trâu mộng, hụt nâng đỉnh","text":"Thạch Mãnh vật ngã một con trâu mộng xanh đen; khi thi nâng đỉnh, nó nhấc được đỉnh lên giữa không trung nhưng chưa qua đầu thì run tay quăng xuống.","anchor":"có mấy đứa còn nhấc được cả những cái chùy đồng nặng hơn trăm cân"}],"tuViMoc":[],"tuVi":"Hài đồng phàm nhân của Thạch Thôn.","nhanMach":[{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Đứa em nhỏ cùng thôn có thể chất kinh người.","ghiChu":"@c0005"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0005"]},{"id":"thach-dai-trang","name":"Thạch Đại Tráng","cn":"","aliases":["Đại Tráng"],"gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (luyện thể) @c0005","trangThai":"song","blurb":"Bé trai chín tuổi của Thạch Thôn, mày rậm mắt to thân hình cao lớn, được khen trời sinh thần lực.","vaiTro":"Thiếu niên có sức lực nổi trội trong đám trẻ Thạch Thôn.","tinhCach":[{"text":"Mạnh mẽ, tự tin vào sức vóc.","chuong":"@c0005"}],"tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0005","tieuDe":"Nâng đỉnh ngàn cân qua đầu","text":"Thạch Đại Tráng chín tuổi nhấc bổng đỉnh đồng ngàn cân qua đỉnh đầu thành công, được cả thôn ca ngợi là trời sinh thần lực.","anchor":"nhấc bổng lên và nhanh chóng nâng quá đỉnh đầu"},{"importance":"normal","chuong":"@c0007","tieuDe":"Dẫn đoàn vào rừng nguyên thủy","text":"Làm thủ lĩnh đoàn trẻ Thạch Thôn, chỉ huy cả bọn lẻn vào rừng nguyên thủy để lấy trứng hung cầm, dặn mọi người cẩn thận và cùng trèo vách theo sau Thạch Hạo.","anchor":"chúng nó trốn người lớn rời khỏi Thạch Thôn để vào rừng"},{"importance":"normal","chuong":"@c0008","tieuDe":"Dẫm vảy hung cầm, tóe máu chân","text":"Cao lớn vạm vỡ và ổn trọng, giục đồng bọn rời tổ; khi dẫm phải tấm vảy kim loại sắc lẻm bị đâm thủng đế giày, tóe máu chân.","anchor":"Đây chính là vảy hung cầm trưởng thành, quả nhiên bất phàm"},{"chuong":"@c0009","importance":"normal","tieuDe":"Kế chọc giận hung cầm cầu viện","text":"Khi bị Thanh Lân Ưng vây trong thạch động, Thạch Đại Tráng đề xuất dốc hết sức chọc giận hung cầm để tạo động tĩnh lớn cho Thạch Thôn nghe thấy mà đến cứu; là một trong ba đứa khỏe nhất chuyên ném thiết mâu vào hai mắt nó.","anchor":"chúng ta dốc hết sức tấn công, chọc giận nó để nó làm ra động tĩnh lớn hơn nữa"}],"tuViMoc":[],"tuVi":"Hài đồng phàm nhân của Thạch Thôn.","nhanMach":[{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Đứa em nhỏ cùng thôn nâng đỉnh sau nó.","ghiChu":"@c0005"},{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Cùng đoàn trẻ, cùng trèo vách","ghiChu":""},{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Bạn cùng nhóm trẻ Thạch Thôn"},{"ten":"Nhị Mãnh","tag":"ban-be","quanHe":"Bạn cùng nhóm trẻ"},{"ten":"Bì Hầu","tag":"ban-be","quanHe":"Bạn cùng nhóm trẻ"},{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Bạn cùng câu giờ chống hung cầm"},{"ten":"Nhị Mãnh","tag":"ban-be","quanHe":"Cùng nhóm ba đứa khỏe nhất ném thiết mâu"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0005","@c0007","@c0008","@c0009"]},{"id":"thach-trung-hau","name":"Thạch Trung Hầu","cn":"","aliases":["Bì Hầu"],"gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (luyện thể) @c0005","trangThai":"song","blurb":"Bé trai tám chín tuổi gầy còm mà khỏe của Thạch Thôn, được cha đặt tên với kỳ vọng phong hầu xưng vương.","vaiTro":"Thiếu niên gầy nhưng có sức của Thạch Thôn.","tinhCach":[{"text":"Gầy gò nhưng khỏe khoắn bất ngờ.","chuong":"@c0005"}],"tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0005","tieuDe":"Quăng cối đá mười mấy mét","text":"Bì Hầu gầy còm mà khỏe, quăng cối đá xa mười mấy mét; cha đặt tên nó là Thạch Trung Hầu với kỳ vọng mai sau phong hầu xưng vương.","anchor":"có mấy đứa còn nhấc được cả những cái chùy đồng nặng hơn trăm cân"},{"importance":"normal","chuong":"@c0007","tieuDe":"Dẫn đường tới sào huyệt Thanh Lân Ưng","text":"Nghe lén thông tin từ Lâm Hổ thúc về tập quán của Thanh Lân Ưng, dẫn đoàn trẻ vào rừng đá tìm tổ hung cầm ở vách núi sâu, rồi cùng ba đứa lớn trèo lên vách.","anchor":"tổ của nó ở trên vách núi sâu trong rừng đá"}],"tuViMoc":[],"tuVi":"Hài đồng phàm nhân của Thạch Thôn.","nhanMach":[{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Cùng thôn, cùng dự cuộc thi thố.","ghiChu":"@c0005"},{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Cùng đoàn trẻ Thạch Thôn","ghiChu":""},{"ten":"Thạch Đại Tráng","tag":"ban-be","quanHe":"Cùng đoàn trẻ, dưới quyền chỉ huy","ghiChu":""}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0005","@c0007"]},{"id":"thach-giao","name":"Thạch Giao","cn":"","aliases":["Thạch Giao","Phi Giao"],"gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Phàm nhân (luyện thể) @c0005","trangThai":"song","blurb":"Bé trai của Thạch Thôn, thử nâng đỉnh nhưng chỉ nhấc được khỏi mặt đất và suýt trẹo hông.","vaiTro":"Thiếu niên góp mặt trong cuộc thi nâng đỉnh của Thạch Thôn.","tinhCach":[{"text":"Hăng hái tham gia thử sức dù chưa đủ lực.","chuong":"@c0005"}],"tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0005","tieuDe":"Suýt trẹo hông khi thử nâng đỉnh","text":"Thạch Giao góp mặt trong cuộc thi nâng đỉnh đồng ngàn cân nhưng chỉ nhấc được khỏi mặt đất, suýt trẹo cả hông.","anchor":"có mấy đứa còn nhấc được cả những cái chùy đồng nặng hơn trăm cân"},{"importance":"normal","chuong":"@c0010","tieuDe":"Tế Tổ Khí thứ hai","text":"Vứt Lang Nha Đại Bổng, ấn tấm da thú cổ lấm máu khô lên ngực; da thú dung hợp thành da thịt, kết kí tự thần bí hiện bóng hung thú, phát tiếng thú gầm rung núi. Kể từng thấy sinh vật hình người cao chọc mây cầm Hắc Thiết Côn hai năm trước.","anchor":"tấm da thú cũ kĩ cổ xưa không ngờ lại dung hợp làm một cùng với lồng ngực gã"},{"importance":"normal","chuong":"@c0013","tieuDe":"Mô tả kẻ địch, báo tin bị chặn cướp","text":"Khuyên nhủ nhà Thủ Sơn, mô tả thằng nhóc Bái Thôn chừng mười bốn mười lăm tuổi trắng trẻo đẹp trai nhưng độc ác. Về sau toàn thân đẫm máu tóc bù xù dẫn tộc nhân chạy về báo bị Bái Thôn chặn giết cướp thú săn; là một trong hai người bắn xuyên được giáp.","anchor":"mấy huynh đệ trước ngực đều lót ba lớp giáp thép tinh chế dày, nhưng toàn bộ đều bị nó bắn xuyên"},{"importance":"normal","chuong":"@c0014","tieuDe":"Gầm khai chiến với Bái Thôn","text":"Khi Bái Thôn ngang ngược không nhường vật săn và khiêu chiến, Thạch Phi Giao gầm lên khai chiến, hai bên hỗn chiến với đại kiếm, cung lớn và Lang Nha Đại Bổng.","anchor":"Vậy thì chiến thôi!"}],"tuViMoc":[],"tuVi":"Hài đồng phàm nhân của Thạch Thôn.","nhanMach":[{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Cùng thôn, cùng dự cuộc thi nâng đỉnh.","ghiChu":"@c0005"}],"tuiDo":{"phapBao":[],"danDuoc":[],"congPhap":[],"linhThu":[],"nguyenLieu":[],"linhThao":[],"khac":[]}},"nguon":["@c0005","@c0010","@c0013","@c0014"]},{"id":"thach-manh-nhi","name":"Thạch Mãnh","aliases":["Nhị Mãnh"],"gioiTinh":"nam","canhGioiCaoNhat":"Phàm nhân (@c0007)","trangThai":"song","blurb":"Đứa trẻ Thạch Thôn da ngăm đen, từng quật ngã trâu mộng, sức đứng sau Thạch Hạo và Đại Tráng.","vaiTro":"Nhân vật phụ — thành viên đoàn trẻ Thạch Thôn.","tinhCach":[{"text":"Da ngăm đen, sức vóc mạnh mẽ, gan dạ","chuong":"@c0007"}],"theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0007","tieuDe":"Ném đá thăm dò tổ hung cầm","text":"Ném đá thử vào Ngô Sào để thăm dò xem Thanh Lân Ưng có trong tổ không, rồi cùng đoàn trèo lên vách đá.","anchor":"để tao ném thử một hòn đá xem sao"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Cùng đoàn trẻ, sức đứng sau Thạch Hạo","ghiChu":""}],"tuiDo":{}},"nguon":["@c0007"]},{"id":"nhi-manh","name":"Nhị Mãnh","gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Thiếu niên Thạch Thôn nước da đen nhẻm, tính ngờ nghệch, cùng nhóm trẻ đi trộm trứng Thanh Lân Ưng.","vaiTro":"Nhân vật phụ","tinhCach":[{"text":"Ngờ nghệch, chất phác","chuong":"@c0008"}],"tabs":{"kinhLich":[{"importance":"normal","chuong":"@c0008","tieuDe":"Trộm trứng Thanh Lân Ưng","text":"Cùng nhóm trẻ chọc tổ Thanh Lân Ưng, vừa chạm vào trứng bích ngọc thì bị tê rần như điện giật, rồi vác một quả trứng chạy về thôn.","anchor":"Đây là cái tổ chim to nhất tao từng chọc"},{"chuong":"@c0009","importance":"normal","tieuDe":"Ném đá và thiết mâu chống hung cầm","text":"Ném tảng đá bằng mặt người trúng đầu Thanh Lân Ưng nhưng đá vỡ nát, vẩy nó cứng như kim loại không hề hấn; sau là một trong ba đứa khỏe nhất chuyên ném thiết mâu vào hai mắt hung cầm để câu giờ.","anchor":"con hung cầm này mình đồng da sắt, quá mạnh mẽ rồi"},{"importance":"normal","chuong":"@c0011","tieuDe":"Hỏi cách xử lý trứng","text":"Hỏi Lâm Hổ thúc phải làm gì với ba quả trứng linh cầm.","anchor":"Thôi, trả trứng lại cho con chim không lông kia đi."}],"nhanMach":[{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Bạn cùng nhóm trẻ Thạch Thôn"},{"ten":"Bì Hầu","tag":"ban-be","quanHe":"Bạn cùng nhóm trẻ"},{"ten":"Thạch Đại Tráng","tag":"ban-be","quanHe":"Bạn cùng nhóm trẻ"},{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Bạn cùng ném thiết mâu vào mắt hung cầm"},{"ten":"Thạch Đại Tráng","tag":"ban-be","quanHe":"Cùng nhóm ba đứa khỏe nhất chống hung cầm"}]},"nguon":["@c0008","@c0009","@c0011"]},{"id":"bi-hau","name":"Bì Hầu","gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Thiếu niên gầy nhom Thạch Thôn, lúc cười giống khỉ núi, cùng nhóm trẻ trộm trứng Thanh Lân Ưng.","vaiTro":"Nhân vật phụ","tinhCach":[{"text":"Nhanh nhẹn, hay tính toán ước lượng","chuong":"@c0008"}],"tabs":{"kinhLich":[{"importance":"normal","chuong":"@c0008","tieuDe":"Vác trứng, ước lượng độ cứng vảy","text":"Vác một quả trứng Thanh Lân Ưng, ước lượng vảy hung cầm cứng đến mức đại kiếm mấy trăm cân cũng khó chém đứt; kỳ vọng người lớn trong thôn sẽ nhìn bọn trẻ khác đi sau vụ trộm trứng.","anchor":"Đây chính là vảy hung cầm trưởng thành, quả nhiên bất phàm"},{"chuong":"@c0009","importance":"normal","tieuDe":"Bắn cung sừng rồng vào hung cầm","text":"Bị đá bay đập trúng cánh tay chảy máu khi chạy trốn; trong động bắn cung sừng rồng vào đầu Thanh Lân Ưng nhưng tên chỉ tóe lửa, không xuyên thủng lớp vẩy.","anchor":"con hung cầm này mình đồng da sắt, quá mạnh mẽ rồi"},{"importance":"minor","chuong":"@c0010","tieuDe":"Thắc mắc chuyện sữa thú","text":"Tò mò hỏi vì sao Nhóc tỳ được uống sữa thú trong khi lũ trẻ khác bị phạt.","anchor":"Tiểu Hồng chính là con chim sẻ toàn thân đỏ rực đó."},{"importance":"normal","chuong":"@c0012","tieuDe":"Cha bị Bái Thôn bắn trọng thương","text":"Cha của Bì Hầu bị người Bái Thôn bắn một mũi tên trúng lá phổi khi đội săn gặp người Bái Thôn tranh mồi, được khiêng về thôn.","anchor":"cha Bì Hầu bị thương không nhẹ, bị người ta bắn một mũi tên, bị thương lá phổi"},{"importance":"minor","chuong":"@c0013","tieuDe":"Khóc ôm cha trọng thương","text":"Khóc lớn ôm lấy cha Thạch Thủ Sơn khi hắn bị bắn tên trọng thương trở về, nhưng bị cha trợn mắt mắng không cho khóc.","anchor":"Bì Hầu khóc lớn"},{"importance":"normal","chuong":"@c0016","tieuDe":"Trả thù Bái Phong","text":"Nhóc trong tộc xông vào đá và chế nhạo Bái Phong vì hắn suýt bắn chết cha mình.","anchor":"xương ngực của Bái Phong lập tức đứt mất mấy cây"}],"nhanMach":[{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Bạn cùng nhóm trẻ Thạch Thôn"},{"ten":"Nhị Mãnh","tag":"ban-be","quanHe":"Bạn cùng nhóm trẻ"},{"ten":"Thạch Đại Tráng","tag":"ban-be","quanHe":"Bạn cùng nhóm trẻ"},{"ten":"Thạch Hạo","tag":"ban-be","quanHe":"Bạn cùng trốn hung cầm trong thạch động"},{"ten":"Nhị Mãnh","tag":"ban-be","quanHe":"Bạn cùng chống hung cầm"},{"ten":"Thạch Thủ Sơn","tag":"cha-me","quanHe":"Cha của Bì Hầu","ghiChu":"Bì Hầu ôm khóc khi cha trọng thương."},{"ten":"Bái Phong","tag":"doi-thu","quanHe":"Xông vào đá và chế nhạo Bái Phong","ghiChu":""}],"tuViMoc":[]},"nguon":["@c0008","@c0009","@c0010","@c0012","@c0013","@c0016"]},{"id":"tu-van","name":"Tử Vân","gioiTinh":"khong-ro","trangThai":"song","blurb":"Chim non thứ ba (lão tam) trong ba con Thanh Lân Ưng, vảy tím, linh tính nhất, xảy ra hiện tượng phản tổ.","vaiTro":"Linh thú thân cận của Thạch Hạo, kế thừa một phần ấn ký Thái Cổ Ma Cầm.","tabs":{"diem":[{"text":"Linh tính nhất, mạnh nổi bật, thông minh hơn cả người khi học cốt văn.","chuong":"@c0012"}],"kinhLich":[{"importance":"normal","chuong":"@c0012","tieuDe":"Lão tam trong ba chim non","text":"Được lũ trẻ đặt tên Tử Vân, là lão tam trong ba con Thanh Lân Ưng; linh tính nhất, từng vỗ cánh ra khỏi thôn xé xác hổ sói, học cốt văn cực hăng và ngày càng thân với Thạch Hạo.","anchor":"Lão đại tên là Đại Bằng, lão nhị Tiểu Thanh, lão tam Tử Vân."},{"importance":"major","chuong":"@c0012","tieuDe":"Phản tổ, Bí cốt bảo thư","text":"Xảy ra hiện tượng phản tổ, kế thừa một phần ấn ký Thái Cổ Ma Cầm; phù văn trong cơ thể được coi là Bí cốt bảo thư, nếu truyền ra sẽ khiến nhiều bộ tộc động lòng.","anchor":"nó xảy ra hiện tượng phản tổ"},{"importance":"normal","chuong":"@c0021","tieuDe":"Tha bảo vật, trúng độc bay về Thạch Thôn","text":"Thanh Lân Ưng cùng nhóc tỳ xuống xác nhận Toan Nghê chết thật, tha về xác Toan Nghê, cánh tay Ác Ma Viên chứa chân huyết và sừng Ly Hỏa Ngưu Ma. Nó lảo đảo vì trúng độc Tử Kim Xà cắn từ trận trước, lại từng bị Huyết Điêu và Thử Vương đánh lén nên độc phát nhanh, gắng gượng bay về Thạch Thôn cầu tộc trưởng giải độc.","anchor":"đại thẩm trúng độc rồi, còn chưa có khử hết"},{"importance":"normal","chuong":"@c0022","tieuDe":"Dẫn đầu người Thạch Thôn cứu viện","text":"Tử Vân cùng Đại Bằng, Tiểu Thanh dẫn đầu người Thạch Thôn xông tới cứu Thạch Hạo khi bị Bái Thôn phục kích.","anchor":"ba con chim non đang vô cùng lo lắng"},{"chuong":"@c0023","importance":"normal","tieuDe":"Lấy thân che tên cho chim mẹ","text":"Cùng Đại Bằng, Tiểu Thanh nhào tới lấy thân che tên cho Thanh Lân Ưng, vảy chưa cứng nên bị thương.","anchor":"Người của Thạch Thôn đã tới rồi, dẫn đầu chính là lão tộc trưởng Thạch Vân Phong"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"dong-minh","quanHe":"Chủ nhân thân thiết","ghiChu":"Cực thân với Thạch Hạo, được nó dạy cốt văn."},{"ten":"Thạch Hạo","tag":"dong-minh","quanHe":"Dẫn người Thạch Thôn tới cứu Thạch Hạo","ghiChu":"@c0022"}],"tuiDo":{}},"nguon":["@c0012","@c0021","@c0022","@c0023"],"aliases":["Thanh Lân Ưng","Đại thẩm"]},{"id":"dai-bang-chim","name":"Đại Bằng","gioiTinh":"khong-ro","trangThai":"song","blurb":"Chim non thứ nhất (lão đại) trong ba con Thanh Lân Ưng.","vaiTro":"Linh thú của Thạch Thôn.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0012","tieuDe":"Lão đại trong ba chim non","text":"Được lũ trẻ đặt tên Đại Bằng, là lão đại trong ba con Thanh Lân Ưng; chỉ một tháng đã dài gần hai mét, được Thạch Hạo dạy cốt văn.","anchor":"Lão đại tên là Đại Bằng, lão nhị Tiểu Thanh, lão tam Tử Vân."},{"chuong":"@c0023","importance":"normal","tieuDe":"Lấy thân che tên cho chim mẹ","text":"Cùng Tiểu Thanh, Tử Vân nhào tới lấy thân che tên cho Thanh Lân Ưng, vảy chưa cứng nên bị thương.","anchor":"Người của Thạch Thôn đã tới rồi, dẫn đầu chính là lão tộc trưởng Thạch Vân Phong"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0012","@c0023"]},{"id":"tieu-thanh-chim","name":"Tiểu Thanh","gioiTinh":"khong-ro","trangThai":"song","blurb":"Chim non thứ hai (lão nhị) trong ba con Thanh Lân Ưng.","vaiTro":"Linh thú của Thạch Thôn.","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0012","tieuDe":"Lão nhị trong ba chim non","text":"Được lũ trẻ đặt tên Tiểu Thanh, là lão nhị trong ba con Thanh Lân Ưng; lớn nhanh trong một tháng, được Thạch Hạo dạy cốt văn.","anchor":"Lão đại tên là Đại Bằng, lão nhị Tiểu Thanh, lão tam Tử Vân."},{"chuong":"@c0023","importance":"normal","tieuDe":"Lấy thân che tên cho chim mẹ","text":"Cùng Đại Bằng, Tử Vân nhào tới lấy thân che tên cho Thanh Lân Ưng, vảy chưa cứng nên bị thương.","anchor":"Người của Thạch Thôn đã tới rồi, dẫn đầu chính là lão tộc trưởng Thạch Vân Phong"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0012","@c0023"]},{"id":"thach-thu-son","name":"Thạch Thủ Sơn","gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Hán tử cường tráng Thạch Thôn, bị Bái Thôn bắn tên xuyên phổi trọng thương nhưng kiên cường không cho vợ con khóc.","vaiTro":"Chiến binh Thạch Thôn, nạn nhân đầu tiên của xung đột Bái Thôn.","tabs":{"kinhLich":[{"importance":"normal","chuong":"@c0013","tieuDe":"Trọng thương trở về","text":"Bị một mũi tên sắt dài một mét ba bắn thủng giáp hộ thân, xuyên qua phổi phải ra tới sau lưng, thân trên loang lổ máu. Kiên cường mắng không cho vợ con khóc, được tộc lão sơ cứu rồi tộc trưởng rút tên, cầm máu và cho thuốc tím cứu chữa.","anchor":"một mũi tên sắt đã bắn thủng giáp hộ thân của hắn, xuyên qua phổi phải ra tới sau lưng"}],"nhanMach":[{"ten":"Bì Hầu","tag":"cha-me","quanHe":"Con trai của Thạch Thủ Sơn","ghiChu":"Bì Hầu khóc lớn ôm cha khi hắn trọng thương."}]},"nguon":["@c0013"]},{"id":"thach-phuc","name":"Thạch Phúc","aliases":["A Phúc thúc"],"gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Người Thạch Thôn thường hái quả mọng cho nhóc tỳ, bị thương trong vụ Bái Thôn chặn cướp.","vaiTro":"Nhân vật phụ Thạch Thôn.","tabs":{"kinhLich":[{"importance":"minor","chuong":"@c0013","tieuDe":"Bị thương trong vụ chặn cướp","text":"Người thường hái quả mọng đỏ cho nhóc tỳ; bị thương đẫm máu trong vụ Bái Thôn chặn giết cướp thú săn, được nhóc tỳ an ủi.","anchor":"đại đội nhân mã ở phía trước."}],"nhanMach":[{"ten":"Thạch Hạo","tag":"an-nhan","quanHe":"Hái quả mọng cho nhóc tỳ","ghiChu":"Được nhóc tỳ an ủi khi bị thương."}]},"nguon":["@c0013"]},{"id":"cha-nhi-manh","name":"Cha của Nhị Mãnh","gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Người Thạch Thôn toàn thân máu, kể lại việc thằng nhóc Bái Thôn bắn tên và lão già lắc đầu.","vaiTro":"Nhân vật phụ Thạch Thôn.","tabs":{"kinhLich":[{"importance":"minor","chuong":"@c0013","tieuDe":"Kể lại vụ chặn cướp","text":"Toàn thân máu trở về, kể lại việc thằng nhóc Bái Thôn bắn tên xuyên giáp và nhờ một lão già Bái Thôn lắc đầu ngăn mới không giết thêm nhiều người.","anchor":"toàn bộ đều bị nó bắn xuyên"},{"importance":"normal","chuong":"@c0016","tieuDe":"Trút giận lên Bái Phong","text":"Nổi giận đùng đùng, vung tay to đánh rách mặt Bái Phong trong lúc người Thạch Thôn trút giận tra tấn tù nhân.","anchor":"xương ngực của Bái Phong lập tức đứt mất mấy cây"}],"nhanMach":[{"ten":"Nhị Mãnh","tag":"cha-me","quanHe":"Cha của Nhị Mãnh","ghiChu":""},{"ten":"Bái Phong","tag":"doi-thu","quanHe":"Đánh rách mặt Bái Phong","ghiChu":""}],"tuViMoc":[]},"nguon":["@c0013","@c0016"]},{"id":"thang-nhoc-bai-thon","name":"Thằng nhóc Bái Thôn","gioiTinh":"nam","theLuc":[{"ten":"Bái Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Thiếu niên Bái Thôn chừng mười bốn mười lăm tuổi, trắng trẻo đẹp trai nhưng độc ác, bắn tên lạnh lùng xuyên thủng giáp ba lớp.","vaiTro":"Kẻ chủ mưu bạo lực của Bái Thôn, đối thủ tiềm năng đáng gờm.","tabs":{"kinhLich":[{"importance":"normal","chuong":"@c0013","tieuDe":"Cầm đầu tấn công Thạch Thôn","text":"Thiếu niên trắng trẻo đẹp trai nhưng lòng dạ độc ác, bắn tên lạnh lùng như giết dã thú; chủ mưu vượt giới cướp thú, suýt bắn xuyên tim người Thạch Thôn, sau đó chặn cướp thú săn và bắn xuyên giáp ba lớp của nhiều người. Được ví như một con Tỳ Hưu trưởng thành.","anchor":"nhìn nó liền giống như đang đối mặt một con Tỳ Hưu trưởng thành"}]},"nguon":["@c0013"]},{"id":"lao-gia-bai-thon","name":"Lão già Bái Thôn","gioiTinh":"nam","theLuc":[{"ten":"Bái Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Người lớn tuổi trong Bái Thôn lắc đầu ngăn, nhờ đó thằng nhóc không giết thêm nhiều người Thạch Thôn.","vaiTro":"Nhân vật phụ Bái Thôn.","tabs":{"kinhLich":[{"importance":"minor","chuong":"@c0013","tieuDe":"Ngăn thằng nhóc giết thêm","text":"Trong vụ chặn cướp, lắc đầu ngăn thằng nhóc Bái Thôn, nhờ đó không giết thêm nhiều người Thạch Thôn.","anchor":"toàn bộ đều bị nó bắn xuyên"}]},"nguon":["@c0013"]},{"id":"thieu-nien-bai-thon","name":"Thiếu niên Bái Thôn","gioiTinh":"nam","theLuc":[{"ten":"Bái Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Thiếu niên Bái Thôn chừng 14-15 tuổi, tuấn tú nhưng ánh mắt lạnh tàn khốc, thần tiễn thủ với cung sừng rồng, thần lực ngang cơ người mạnh nhất Thạch Thôn.","vaiTro":"Đối thủ Bái Thôn, thần tiễn thủ tài năng kinh người","tabs":{"diem":[{"text":"Thiếu niên 14-15 tuổi đã ngang cơ người mạnh nhất Thạch Thôn, thần lực nâng đỉnh đồng năm sáu ngàn cân.","chuong":"@c0014"}],"kinhLich":[{"importance":"normal","chuong":"@c0014","tieuDe":"Bắn tên lạnh, đấu tiễn với Thạch Lâm Hổ","text":"Thiếu niên Bái Thôn dùng cung sừng rồng bắn mũi tên lạnh cứa rách da cổ Thạch Lâm Hổ, rồi đấu tiễn ngang tài mười mấy mũi tên. Trong hỗn chiến y bắn liền bốn mũi nhắm giết Thạch Hạo nhưng bị nhóc tỳ chém hất mũi cuối, khiến Thạch Hạo lao thẳng tới tấn công y.","anchor":"Nhóc tỳ nhảy lên, lao thẳng tới chỗ thiếu niên Bái Thôn kia!"},{"importance":"normal","chuong":"@c0015","tieuDe":"Bại trận trước Thạch Hạo","text":"Bái Phong thần lực kinh người, rung hai tay đủ nâng năm sáu cái đỉnh đồng, dùng cung tên sắt, trường mâu Huyết Văn Thiết và tên nỏ giấu sau lưng tấn công Thạch Hạo. Sau mấy chục chiêu, hắn bị đứa bé chưa bốn tuổi đánh phun máu tươi, bay ngang đụng gãy cành cây rơi xuống đất.","anchor":"Bái Phong không ngừng kéo cung, bắn liên tiếp tám mũi tên sắt"},{"importance":"normal","chuong":"@c0016","tieuDe":"Bị bắt và tra tấn thê thảm","text":"Thiếu niên thiên tư của Bái Thôn bị Thạch Hạo hạ gục và bắt sống, bị người Thạch Thôn thay nhau đá đấm gãy nhiều xương, mặt rách, gần không còn hình người; Bái Thôn phải giao vũ khí bồi thường mới chuộc được hắn.","anchor":"xương ngực của Bái Phong lập tức đứt mất mấy cây"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Lâm Hổ","tag":"doi-thu","quanHe":"Đối thủ đấu tiễn ngang tài"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Nhắm bắn giết nhưng bị nhóc tỳ chém hất mũi tên và phản công"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Đối thủ giao đấu","ghiChu":"Bị Thạch Hạo đánh bại phun máu bay ngang."},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Bị Thạch Hạo đá gục và bắt sống","ghiChu":"Trở thành tù nhân của Thạch Thôn."},{"ten":"Thạch Lâm Hổ","tag":"doi-thu","quanHe":"Bị Thạch Lâm Hổ ngồi lên người, dọa chặt đầu","ghiChu":""}],"tuiDo":{"phapBao":[{"ten":"Cung sừng rồng","loai":"vũ khí","moTa":"Cây cung lớn màu đen làm từ sừng rồng, cao quá nửa thân người.","nguon":"@c0014"}]}},"nguon":["@c0014","@c0015","@c0016"],"aliases":["Thiếu niên Bái Thôn"]},{"id":"thu-linh-doi-san-bai-thon","name":"Thủ lĩnh đội săn Bái Thôn","gioiTinh":"nam","theLuc":[{"ten":"Bái Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Trung niên Bái Thôn vạm vỡ cao 2m4, ngang ngược, thủ lĩnh đội săn khiêu chiến Thạch Thôn.","vaiTro":"Thủ lĩnh đội săn Bái Thôn","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0014","tieuDe":"Ngang ngược khiêu chiến Thạch Thôn","text":"Thủ lĩnh đội săn Bái Thôn cao 2m4 vạm vỡ ngang ngược không nhường vật săn, khiêu chiến Thạch Thôn dẫn tới hai bên khai chiến hỗn loạn.","anchor":"Vậy thì chiến thôi!"},{"importance":"normal","chuong":"@c0022","tieuDe":"Cầm đầu phục kích Thạch Hạo","text":"Bắn tên sắt sạt qua cổ họng Thạch Hạo mở màn phục kích, dẫn hơn hai mươi người Bái Thôn vây bắt. Bị Bảo Nguyệt chém rách bụng suýt lòi ruột, sắc mặt tái nhợt ra lệnh rút lui.","anchor":"một mũi tên sắt lạnh lẽo bắn sạt qua cổ họng nó"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Phục kích Thạch Hạo nhưng bị chém rách bụng","ghiChu":"@c0022"}],"tuiDo":{}},"nguon":["@c0014","@c0022"]},{"id":"thach-phi-giao","name":"Thạch Phi Giao","gioiTinh":"nam","theLuc":[{"ten":"Thạch Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"Không rõ (@c0015)","trangThai":"song","blurb":"Người của Thạch Thôn, chứng kiến trận đấu và mắng Bái Phong ác độc.","vaiTro":"Người Thạch Thôn","tinhCach":[{"text":"Nhìn xa, dự đoán tính ác của kẻ khác","chuong":"@c0015"}],"tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0015","tieuDe":"Mắng Bái Phong ác độc","text":"Thạch Phi Giao tức giận mắng Bái Phong ác độc khi hắn giở chiêu bẩn giấu tên nỏ sau lưng bắn lén Thạch Hạo, và dự đoán tiểu tử này sau khi trưởng thành sẽ là một tai họa.","anchor":"hàng loạt điểm sáng khuếch tán ra đánh vỡ toàn bộ tên nỏ"},{"importance":"normal","chuong":"@c0016","tieuDe":"Đá gãy xương Bái Phong","text":"Hung hăng đá một cước làm gãy mấy cây xương ngực của Bái Phong, quát mắng đòi bồi thường trong trận thắng của Thạch Thôn.","anchor":"xương ngực của Bái Phong lập tức đứt mất mấy cây"},{"importance":"normal","chuong":"@c0017","tieuDe":"Kích động trước di thể Toan Nghê","text":"Thanh niên trai tráng trong tộc, mắt đỏ lên vì kích động khi bàn về di thể Toan Nghê — kho báu với chân huyết và Nguyên Thủy Bảo Phù.","anchor":"tộc chúng ta coi như cũng có một môn Bảo Thuật rồi"},{"importance":"normal","chuong":"@c0018","tieuDe":"Trọng thương trước Cự Bưu","text":"Ức chế vì bỏ lỡ di thể Toan Nghê; khi hai con Bưu tấn công thôn nhân, vung kiếm bản to cùng Thạch Lâm Hổ xông tới nhưng bị đánh bay vũ khí, rách bụng trọng thương, sau đó cổ vũ Thạch Hạo.","anchor":"Lại là loài Bưu đáng sợ, hơn nữa còn những hai con!"},{"chuong":"@c0023","importance":"normal","tieuDe":"Theo cứu viện Thạch Hạo","text":"Theo Thạch Vân Phong tới cứu viện, tham gia hỗn chiến chống Bái Thôn.","anchor":"Người của Thạch Thôn đã tới rồi, dẫn đầu chính là lão tộc trưởng Thạch Vân Phong"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"dong-minh","quanHe":"Người cùng Thạch Thôn","ghiChu":"Bênh Thạch Hạo, mắng Bái Phong khi hắn dùng chiêu bẩn."},{"ten":"Bái Phong","tag":"doi-thu","quanHe":"Người thôn đối địch","ghiChu":"Mắng Bái Phong ác độc, dự đoán hắn sẽ thành tai họa."},{"ten":"Bái Phong","tag":"doi-thu","quanHe":"Đá gãy xương Bái Phong","ghiChu":""},{"ten":"Bái Lý Thanh","tag":"doi-thu","quanHe":"Đối thủ trong trận hỗn chiến Bái Thôn","ghiChu":"@c0023"}],"tuiDo":{}},"nguon":["@c0015","@c0016","@c0017","@c0018","@c0023"]},{"id":"thieu-nien-cang-bai-thon","name":"Thiếu niên trên cáng (Bái Thôn)","gioiTinh":"nam","theLuc":[{"ten":"Bái Thôn","trangThai":"gan-bo"}],"trangThai":"song","blurb":"Thiếu niên Bái Thôn sắc mặt tái, ánh mắt lạnh, đi cùng viện binh Bái Thôn.","vaiTro":"Đối thủ","tabs":{"diem":[],"kinhLich":[{"importance":"normal","chuong":"@c0022","tieuDe":"Theo viện binh Bái Thôn","text":"Nằm trên cáng thưởng thức vòng răng thú, đi cùng làn sóng viện binh Bái Thôn đang kéo tới sau khi đội săn thú rút lui.","anchor":"kéo người bị trọng thương nhanh chóng rút lui"}],"tuViMoc":[],"nhanMach":[],"tuiDo":{}},"nguon":["@c0022"]},{"id":"bai-ly-thanh","name":"Bái Lý Thanh","cn":"","aliases":["Tộc trưởng Bái Thôn"],"gioiTinh":"nam","theLuc":[{"ten":"Bái Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Lão tộc trưởng Bái Thôn giả nhân từ, dùng mưu phục kích cướp bảo thể Toan Nghê.","vaiTro":"Tộc trưởng Bái Thôn, kẻ cầm đầu cuộc phục kích Thạch Hạo.","tinhCach":[{"text":"Giả nhân từ, thâm hiểm, sẵn sàng phá quy củ Đại Hoang vì lợi ích tộc","chuong":"@c0023"}],"tabs":{"diem":[{"text":"Giả khuyên nhủ để trói chân đối phương rồi ra lệnh giết","chuong":"@c0023"}],"kinhLich":[{"chuong":"@c0023","importance":"normal","tieuDe":"Dẫn Bái Thôn phục kích cướp bảo thể","text":"Dẫn hơn trăm người Bái Thôn phục kích Thạch Hạo, giả nhân từ khuyên giao bảo thể Toan Nghê nhưng thực chất ra lệnh bắn Thanh Lân Ưng để trói chân nhóc, tiết lộ Tế Linh của tộc sắp đột phá cần chân huyết.","anchor":"Tế Linh của tộc ta sắp đột phá rồi, cũng cần gấp một lượng chân huyết lớn"},{"importance":"minor","chuong":"@c0024","tieuDe":"Quát Bái Phong, đòi đoạt lại Bảo cụ","text":"Tộc trưởng Bái thôn quát Bái Phong giết nhóc tỳ, sau đó hô đoạt lại Bảo cụ khi Bái Phong bại trận và bị cướp mất."}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Kẻ thù, kẻ mưu cướp bảo thể và giết nhóc","ghiChu":"Ra lệnh vây giết Thạch Hạo @c0023"},{"ten":"Thạch Vân Phong","tag":"doi-thu","quanHe":"Bị Thạch Vân Phong quát vì phá quy củ Đại Hoang","ghiChu":"@c0023"}],"tuiDo":{}},"nguon":["@c0023","@c0024"]},{"id":"bai-son","name":"Bái Sơn","cn":"","aliases":["Thủ lĩnh đội săn thú Bái Thôn"],"gioiTinh":"nam","theLuc":[{"ten":"Bái Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Thủ lĩnh đội săn thú Bái Thôn, núp bắn xuyên tay Thạch Hạo.","vaiTro":"Thủ lĩnh săn thú Bái Thôn, tay bắn cung tập kích.","tinhCach":[{"text":"Hiểm độc, chuyên núp tập kích","chuong":"@c0023"}],"tabs":{"diem":[{"text":"Trước bị trăng bạc rạch bụng, sau núp lùm cây bắn lén","chuong":"@c0023"}],"kinhLich":[{"chuong":"@c0023","importance":"normal","tieuDe":"Bắn xuyên tay Thạch Hạo","text":"Sắc mặt tái nhợt do trước bị trăng bạc rạch bụng, núp trong lùm cây nhắm tim yết hầu bắn xuyên tay Thạch Hạo.","anchor":"chính hắn đã bắn tên xuyên tay của nhóc tỳ"},{"importance":"minor","chuong":"@c0024","tieuDe":"Hô chiếm lại Bảo cụ","text":"Thủ lĩnh đội đi săn Bái thôn cùng hô Nhanh chiếm lại Bảo cụ khi Bái Phong mất Bảo cụ vào tay nhóc tỳ."}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Đối thủ, bắn lén xuyên tay","ghiChu":"@c0023"}],"tuiDo":{}},"nguon":["@c0023","@c0024"]},{"id":"bai-phong","name":"Bái Phong","cn":"","aliases":["Thiếu niên trên cáng (Bái Thôn)","Thiếu niên Bái Thôn","nhóc tỳ (Bái Phong)"],"gioiTinh":"nam","theLuc":[{"ten":"Bái Thôn","trangThai":"gan-bo"}],"canhGioiCaoNhat":"","trangThai":"song","blurb":"Thiếu niên thiên tài Bái Thôn từng thua Thạch Hạo, dùng Bảo Cụ vòng răng thú tập kích báo thù.","vaiTro":"Thiên tài Bái Thôn, đối thủ ôm hận Thạch Hạo.","tinhCach":[{"text":"Ôm hận, lạnh lùng tập kích; tự nhận lần trước quá hiền lành nên thả đối phương, lần này quyết không tha","chuong":"@c0023"}],"tabs":{"diem":[{"text":"Cốt Văn còn dùng được cả Bảo Cụ khiến đám đông kinh ngạc","chuong":"@c0023"}],"kinhLich":[{"chuong":"@c0023","importance":"normal","tieuDe":"Tập kích Thạch Hạo bằng Bảo Cụ","text":"Từng bị Thạch Hạo đánh bại và bị người Thạch Thôn đánh gãy xương, nay dùng Bảo Cụ tập kích đánh xuyên sáu bảy người Thạch Thôn, làm rách vai Thạch Hạo, một đốm sáng suýt xuyên yết hầu.","anchor":"Không chỉ ngươi mới có Bảo Cụ, ta cũng có đây"},{"chuong":"@c0023","importance":"normal","tieuDe":"Lộ Bảo Cụ vòng răng thú","text":"Điều khiển mưa ánh sáng vờn quanh cổ tay hóa thành vòng răng thú trắng tinh óng ánh, trọng thương đám người trung niên tạng phủ bị xé rách, tuyên bố lần này quyết không tha.","anchor":"Lần này ta tuyệt đối sẽ không tha cho ngươi đâu!"},{"importance":"normal","chuong":"@c0024","tieuDe":"Bại trận, bị tàn phế","text":"Dùng Bảo cụ 42 răng thú tấn công nhóc tỳ nhưng phát hiện đối phương nắm giữ sức mạnh Cốt văn thần bí. Khi nhóc tỳ ngộ thêm tầng Bảo thuật, Bái Phong bị đánh phọt máu, bị đá vỡ mặt gãy xương, cuối cùng bị cắt đứt cả tứ chi và mất Bảo cụ.","anchor":"Mày không phải dùng Bảo cụ, mày sử dụng... Sức mạnh Cốt văn!!!"}],"tuViMoc":[],"nhanMach":[{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Kẻ thù, từng thua Thạch Hạo nay tập kích báo thù","ghiChu":"@c0023"},{"ten":"Thạch Hạo","tag":"doi-thu","quanHe":"Bị nhóc tỳ đánh bại, tàn phế và cướp Bảo cụ"}],"tuiDo":{"khac":[{"ten":"Vòng răng thú (Bảo Cụ)","loai":"bảo cụ","trangThai":"dang-co","moTa":"Mưa ánh sáng vờn quanh cổ tay hóa thành vòng răng thú trắng tinh óng ánh, phóng ra điểm sáng như mưa sao băng, lực sát thương kinh người, đánh xuyên tạng phủ người.","nguon":"@c0023"}]}},"nguon":["@c0023","@c0024"]}]};
